const DEFAULT_THEME_KEY = 'cozyGrocery';

// Applied app-wide via a global !important rule (see themeCssVars), since
// most text elements set their font-family inline rather than through a
// shared class - a plain CSS var alone wouldn't be able to override that
// without !important backing it.
const FONT_PRESETS = {
  quicksandNunito: { label: 'Quicksand + Nunito (Default)', family: "'Quicksand', 'Nunito', sans-serif" },
  poppinsInter: { label: 'Poppins + Inter (Modern)', family: "'Poppins', 'Inter', sans-serif" },
  playfairSource: { label: 'Playfair Display + Source Sans (Elegant)', family: "'Playfair Display', 'Source Sans 3', serif" },
  georgiaVerdana: { label: 'Georgia + Verdana (Classic)', family: "Georgia, 'Verdana', serif" },
  courierMono: { label: 'Courier Mono (Utilitarian)', family: "'IBM Plex Mono', 'Courier New', monospace" },
};
const DEFAULT_FONT_KEY = 'quicksandNunito';

// Darkens a #rrggbb hex color by `percent` (0-100), used to derive the
// bottom-of-gradient shade for a custom sidebar color the same way each
// THEME already pairs a `blueprint` color with a darker `blueprintDeep`.
function shadeHex(hex, percent) {
  if (!hex || !/^#[0-9a-fA-F]{6}$/.test(hex)) return hex;
  const num = parseInt(hex.slice(1), 16);
  const amt = Math.round(2.55 * percent);
  const r = Math.max(0, (num >> 16) - amt);
  const g = Math.max(0, ((num >> 8) & 0x00ff) - amt);
  const b = Math.max(0, (num & 0x0000ff) - amt);
  return `#${(0x1000000 + r * 0x10000 + g * 0x100 + b).toString(16).slice(1)}`;
}

function themeCssVars(theme, fontFamily, customInk, customPanelBg, customSidebarBg) {
  return `
    :root {
          --blueprint: ${theme.blueprint};
          --blueprint-deep: ${theme.blueprintDeep};
          --line: ${theme.line};
          --line-dim: ${theme.lineDim};
          --paper: ${theme.paper};
          --paper-dim: ${theme.paperDim};
          --ink: ${customInk || theme.ink};
          --amber: ${theme.amber};
          --amber-deep: ${theme.amberDeep};
          --green: ${theme.green};
          --red: ${theme.red};
          --panel-bg: ${customPanelBg || '#ffffff'};
          --sidebar-bg: ${customSidebarBg || theme.blueprint};
          --sidebar-bg-deep: ${customSidebarBg ? shadeHex(customSidebarBg, 18) : theme.blueprintDeep};
          --font-body: ${fontFamily || FONT_PRESETS[DEFAULT_FONT_KEY].family};
    }
    /* Most text elements in this app set font-family inline rather than
       through a shared class, so a plain CSS var alone can't override
       them - !important is required to make the font picker actually
       take effect app-wide. Text COLOR mostly already flows through
       var(--ink) directly in shared styles, so it doesn't need the same
       !important treatment. */
    .depot-wrap, .depot-wrap * { font-family: var(--font-body) !important; }
  `;
}

export default function InventorySystem() {
  const [user, setUser] = useState(null);
  const [authChecked, setAuthChecked] = useState(false);
  const [introDone, setIntroDone] = useState(() => {
    try { return sessionStorage.getItem('stockit_intro_shown') === '1'; } catch { return false; }
  });
  const [myProfile, setMyProfile] = useState(null);
  const [employerProfile, setEmployerProfile] = useState(null);
  const [profileChecked, setProfileChecked] = useState(false);
  const [pendingUsers, setPendingUsers] = useState([]);
  const [approvedUsers, setApprovedUsers] = useState([]);
  const [branding, setBranding] = useState(null);
  const [tenantBranding, setTenantBranding] = useState(null);
  const [items, setItems] = useState([]);
  const [movements, setMovements] = useState([]);
  const [suppliers, setSuppliers] = useState([]);
  const [categories, setCategories] = useState([]);
  const [locations, setLocations] = useState([]);
  const [deliveryStatuses, setDeliveryStatuses] = useState({});
  const [sales, setSales] = useState([]);
  const [orders, setOrders] = useState([]);
  const [restocks, setRestocks] = useState([]);
  const [shops, setShops] = useState([]);
  const [activeShopId, setActiveShopId] = useState(null);
  const [loginLogs, setLoginLogs] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [view, setView] = useState('overview');
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [sortKey, setSortKey] = useState('name');
  const [itemModal, setItemModal] = useState(null);
  const [moveModal, setMoveModal] = useState(null);
  const [supplierModal, setSupplierModal] = useState(null);
  const [orderModal, setOrderModal] = useState(null);
  const [restockModal, setRestockModal] = useState(false);
  const [assignModal, setAssignModal] = useState(null);
  const [markupModal, setMarkupModal] = useState(null);
  const [returnModal, setReturnModal] = useState(null);
  const [subscriptionModal, setSubscriptionModal] = useState(null);
  const [selectedStaffUid, setSelectedStaffUid] = useState('');
  const [confirmModal, setConfirmModal] = useState(null); // {kind: 'item'|'supplier'|'order', target}
  const [deliveryStatusModal, setDeliveryStatusModal] = useState(null);
  const [toast, setToast] = useState(null);

  // history filters
  const [histSearch, setHistSearch] = useState('');
  const [histType, setHistType] = useState('All');
  const [histItem, setHistItem] = useState('All');

  // Auth: track sign-in state
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      setUser(u);
      setAuthChecked(true);
    });
    return unsub;
  }, []);

  // Approval: ensure a users/{uid} profile exists, then subscribe to it live
  useEffect(() => {
    if (!user) { setMyProfile(null); setProfileChecked(false); return; }
    let unsub;
    setProfileChecked(false);
    (async () => {
      try {
        const ref = doc(db, 'users', user.uid);
        const snap = await getDoc(ref);
        if (!snap.exists()) {
          const isGoogleSignIn = user.providerData?.some((p) => p.providerId === 'google.com');
          await setDoc(ref, isGoogleSignIn ? {
            // First-time Google sign-in always creates a new Client Admin
            // account (a new tenant/business), pending Super Admin
            // approval - this is the ONLY self-serve signup path now;
            // Google sign-in is Client-Admin-only by design.
            email: user.email || '', approved: false, isAdmin: false, role: 'client', createdAt: Date.now(),
            fullName: user.displayName || '', username: '', contactNumber: '', address: '',
            userIdNumber: generateUserIdNumber(), agreedToTermsAt: Date.now(),
          } : {
            // Safety-net bootstrap path: an authenticated user with no
            // profile doc at all (shouldn't normally happen - staff are
            // always created with a profile already in place by their
            // Client Admin). Inert: unapproved, tenant-less, can't
            // read/write anything.
            email: user.email || '', approved: false, isAdmin: false, role: 'staff', createdAt: Date.now(),
          }, { merge: true });
        }
      } catch (e) {
        console.error('Profile bootstrap error:', e);
      }
      unsub = onSnapshot(doc(db, 'users', user.uid), (d) => {
        setMyProfile(d.exists() ? d.data() : null);
        setProfileChecked(true);
      }, logSnapErr('myProfile'));
    })();
    return () => { if (unsub) unsub(); };
  }, [user]);

  const myRole = resolveRole(myProfile);
  const isManager = myRole === 'superadmin' || myRole === 'client';

  // Multi-tenancy: every piece of business data (items, suppliers, sales,
  // categories, etc.) is stamped with the `ownerId` of the tenant it belongs
  // to. A Client Admin IS a tenant, so their ownerId is their own uid. Staff
  // don't own a tenant - they inherit the ownerId of whichever Client Admin
  // created them (stored on their profile as `parentId`). Super Admin gets
  // their own tenant too, so their own inventory/sales stay separate from
  // every client's data, but they retain unscoped visibility into the
  // `users` collection so they can approve/manage accounts platform-wide.
  const ownerId = !user ? null
    : myRole === 'staff' ? (myProfile?.parentId || null)
    : user.uid;

  // Staff read their employer's (Client Admin's) profile doc to check
  // subscription status - a plain get() on one known document, not a list
  // query, so it's not subject to the Firestore list-query limitation
  // we've hit elsewhere in this app.
  useEffect(() => {
    if (myRole !== 'staff' || !ownerId) { setEmployerProfile(null); return; }
    const unsub = onSnapshot(doc(db, 'users', ownerId), (d) => {
      setEmployerProfile(d.exists() ? d.data() : null);
    }, logSnapErr('employerProfile'));
    return unsub;
  }, [myRole, ownerId]);

  // Whichever profile actually carries subscription data for this
  // session: a Client Admin's own subscription, or (for staff) their
  // employer's. Computed live against today's date every render - see the
  // subscription helpers for why this can't just trust a stored flag.
  const mySubscription = myRole === 'staff' ? employerProfile?.subscription : myProfile?.subscription;
  const accessPaused = (myRole === 'client' || myRole === 'staff') && !isSubscriptionActive(mySubscription);

  // Activity log: record a "login" entry each time a session starts. This is
  // a client-side approximation - it can't distinguish "just signed in" from
  // "reopened the app with a still-valid session," since both look the same
  // to the client SDK. Logout is recorded explicitly via handleSignOut below.
  useEffect(() => {
    // Wait for the tenant (ownerId) to resolve from the profile before
    // logging, so the entry is correctly scoped to the right Client Admin.
    if (!user || !ownerId) return;
    (async () => {
      try {
        const logId = 'l' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'loginLogs', logId), {
          uid: user.uid, email: user.email || '', type: 'login', timestamp: Date.now(), ownerId,
        });
      } catch (e) {
        console.error('Login log error:', e);
      }
    })();
  }, [user?.uid, ownerId]);

  const handleSignOut = async () => {
    if (user) {
      try {
        const logId = 'l' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'loginLogs', logId), {
          uid: user.uid, email: user.email || '', type: 'logout', timestamp: Date.now(), ownerId,
        });
      } catch (e) {
        console.error('Logout log error:', e);
      }
    }
    await signOut(auth);
  };

  // Branding (custom logo + theme): public read, so this works even on the
  // signed-out login screen. This is the PLATFORM default - Super Admin
  // only - applied at sign-in and to any tenant that hasn't set their own.
  useEffect(() => {
    const unsub = onSnapshot(doc(db, 'config', 'branding'), (d) => {
      setBranding(d.exists() ? d.data() : {});
    }, (err) => { logSnapErr('platformBranding')(err); setBranding({}); });
    return unsub;
  }, []);

  // Per-tenant branding override: each Client Admin can customize their own
  // logo/theme independently, without affecting the platform default or any
  // other tenant. Only meaningful once ownerId is known (i.e. after login),
  // since it lives at config/branding_{ownerId}.
  useEffect(() => {
    if (!ownerId) { setTenantBranding(null); return; }
    const unsub = onSnapshot(doc(db, 'config', 'branding_' + ownerId), (d) => {
      setTenantBranding(d.exists() ? d.data() : {});
    }, (err) => { logSnapErr('tenantBranding')(err); setTenantBranding({}); });
    return unsub;
  }, [ownerId]);

  // Effective branding: a tenant's own override wins field-by-field, falling
  // back to the platform default for anything the tenant hasn't customized.
  const effectiveBranding = {
    logoDataUri: tenantBranding?.logoDataUri ?? branding?.logoDataUri,
    themeKey: tenantBranding?.themeKey ?? branding?.themeKey,
    fontKey: tenantBranding?.fontKey ?? branding?.fontKey,
    customInk: tenantBranding?.customInk ?? branding?.customInk,
    customPanelBg: tenantBranding?.customPanelBg ?? branding?.customPanelBg,
    customSidebarBg: tenantBranding?.customSidebarBg ?? branding?.customSidebarBg,
    animationTheme: tenantBranding?.animationTheme ?? branding?.animationTheme,
  };
  const effectiveLogo = effectiveBranding.logoDataUri || LOGO_DATA_URI;
  const activeTheme = THEMES[effectiveBranding.themeKey] || THEMES[DEFAULT_THEME_KEY];
  const activeFontFamily = (FONT_PRESETS[effectiveBranding.fontKey] || FONT_PRESETS[DEFAULT_FONT_KEY]).family;

  // Super Admin manages Team Access for the whole platform (every account) -
  // an unfiltered collection listener, which works fine for them since
  // isSuperAdmin() alone (not combined with per-document field matching)
  // is trivially provable across the whole collection.
  //
  // A Client reads each of THEIR staff individually, driven by the
  // `staffUids` array recorded on their own profile (see
  // createStaffAccount). This sidesteps a Firestore list-query edge case:
  // a collection query filtered by `where('parentId', '==', myUid)` -
  // logically sound and confirmed correct against the security rules -
  // was nonetheless silently denied by Firestore with no reliable fix
  // found. Reading each staff document individually (a plain get(), not a
  // list) avoids that edge case entirely.
  const staffUidsKey = JSON.stringify(myProfile?.staffUids || []);
  useEffect(() => {
    if (!user || !isManager) { setPendingUsers([]); setApprovedUsers([]); return; }

    if (myRole === 'superadmin') {
      const unsub = onSnapshot(collection(db, 'users'), (snap) => {
        const all = snap.docs.map((d) => ({ id: d.id, ...d.data(), role: resolveRole(d.data()) }));
        setPendingUsers(all.filter((u) => !u.approved));
        setApprovedUsers(all.filter((u) => u.approved));
      }, logSnapErr('teamRoster'));
      return unsub;
    }

    const staffUids = JSON.parse(staffUidsKey);
    if (staffUids.length === 0) { setPendingUsers([]); setApprovedUsers([]); return; }

    const docsMap = {};
    const refresh = () => {
      const all = Object.values(docsMap);
      setPendingUsers(all.filter((u) => !u.approved));
      setApprovedUsers(all.filter((u) => u.approved));
    };
    const unsubs = staffUids.map((uid) =>
      onSnapshot(doc(db, 'users', uid), (d) => {
        if (d.exists()) docsMap[uid] = { id: d.id, ...d.data(), role: resolveRole(d.data()) };
        else delete docsMap[uid];
        refresh();
      }, logSnapErr('teamRoster'))
    );
    return () => unsubs.forEach((u) => u());
  }, [user, isManager, myRole, staffUidsKey]);

  // Lets a Client Admin (or Super Admin, for support) provision a Staff
  // account directly - no self-signup/approval step. Uses a throwaway
  // secondary Firebase App instance so creating the new auth user doesn't
  // sign the admin themselves out of their own session (the Firebase client
  // SDK otherwise switches the active session to whichever user was most
  // recently created).
  const createStaffAccount = async ({ password, fullName, username, contactNumber, address }) => {
    if (!can(myRole, 'createStaff') || !ownerId) {
      showToast("You don't have permission to add staff");
      return { ok: false };
    }
    let secondaryApp;
    try {
      // The Inventory ID doubles as the staff member's login username AND
      // (deterministically, via inventoryIdToStaffEmail) the seed for a
      // fake internal email - Firebase's password auth fundamentally
      // requires *some* email, real or not, but nothing about it is ever
      // shown to the staff member or usable by them directly.
      const inventoryId = generateUserIdNumber();
      const staffEmail = inventoryIdToStaffEmail(inventoryId);

      secondaryApp = initializeApp(auth.app.options, 'staff-creation-' + Date.now());
      const secondaryAuth = getAuth(secondaryApp);
      // Critical: without this, the secondary app shares the SAME
      // persisted auth storage as our own (primary) session by default -
      // signing in/out a brand-new user on it can silently corrupt the
      // admin's own active session, causing their live listeners to start
      // throwing permission-denied shortly after. In-memory persistence
      // keeps it fully isolated.
      await setPersistence(secondaryAuth, inMemoryPersistence);
      const cred = await createUserWithEmailAndPassword(secondaryAuth, staffEmail, password);
      await setDoc(doc(db, 'users', cred.user.uid), {
        email: staffEmail, approved: true, isAdmin: false, role: 'staff',
        parentId: ownerId, createdAt: Date.now(), createdBy: user.uid,
        fullName: (fullName || '').trim(), username: (username || '').trim(),
        contactNumber: (contactNumber || '').trim(), address: (address || '').trim(),
        userIdNumber: inventoryId,
      });
      // Record this staff member on OUR OWN profile too. This is what lets
      // Team Access find "my staff" via a simple read of our own document
      // instead of a collection-wide query for "anyone whose parentId is
      // me" - the former is a plain, reliable single-document read; the
      // latter turned out to be an unreliable Firestore list-query edge
      // case that silently denied results with no clear fix.
      await setDoc(doc(db, 'users', user.uid), {
        staffUids: arrayUnion(cred.user.uid),
      }, { merge: true });
      await signOut(secondaryAuth);
      playAddSound();
      logActivity('staff_created', { targetEmail: fullName || inventoryId, targetUid: cred.user.uid });
      showToast(`Staff account created — Inventory ID: ${inventoryId}`);
      return { ok: true, inventoryId };
    } catch (e) {
      const msg = e?.code === 'auth/weak-password'
        ? 'Password should be at least 6 characters'
        : 'Could not create staff account — check your connection';
      showToast(msg);
      return { ok: false, error: e };
    } finally {
      if (secondaryApp) { try { await deleteApp(secondaryApp); } catch {} }
    }
  };

  const approveUser = async (uid) => {
    try {
      await setDoc(doc(db, 'users', uid), { approved: true }, { merge: true });
      showToast('Account approved');
    } catch (e) {
      showToast('Could not approve — check your connection');
    }
  };

  const denyUser = async (uid) => {
    try {
      await deleteDoc(doc(db, 'users', uid));
      showToast('Request removed');
    } catch (e) {
      showToast('Could not remove request — check your connection');
    }
  };

  const revokeUser = async (uid) => {
    try {
      await deleteDoc(doc(db, 'users', uid));
      // Only relevant when a Client revokes their own staff (their roster
      // is driven by this array) - harmless no-op for Super Admin removing
      // any other account, since Super Admin's list isn't array-driven.
      if (myRole === 'client') {
        try { await setDoc(doc(db, 'users', user.uid), { staffUids: arrayRemove(uid) }, { merge: true }); } catch {}
      }
      showToast('Access revoked');
    } catch (e) {
      showToast('Could not revoke access — check your connection');
    }
  };

  const changeUserRole = async (uid, newRole) => {
    if (myRole !== 'superadmin') return;
    try {
      await setDoc(doc(db, 'users', uid), { role: newRole }, { merge: true });
      showToast(`Role updated to ${ROLES[newRole] || newRole}`);
    } catch (e) {
      showToast('Could not update role — check your connection');
    }
  };

  // Super Admin only. Month/Year still label and identify each period (used
  // to file it under a specific month for the Monthly Report and history
  // list), but the actual startDate/endDate are now whatever the admin
  // sets them to - not forced to calendar-month boundaries, so a
  // subscription can start/end on any specific date. Creating a period for
  // a month/year that doesn't exist yet in this client's history appends a
  // new entry; picking one that already exists updates it in place.
  const saveSubscriptionPeriod = async (clientUid, { month, year, startDate, endDate, paymentStatus }) => {
    if (myRole !== 'superadmin') { showToast("You don't have permission to manage subscriptions"); return; }
    const client = approvedUsers.find((u) => u.id === clientUid);
    if (!client) { showToast('Client not found'); return; }
    if (!startDate || !endDate || endDate < startDate) { showToast('Pick a valid start and end date (end must be after start)'); return; }
    const history = client.subscription?.history || [];
    const idx = history.findIndex((p) => p.month === month && p.year === year);
    const isNew = idx < 0;
    const entry = { month, year, startDate, endDate, paymentStatus, setAt: Date.now(), setBy: user.email || user.uid };
    const newHistory = isNew ? [...history, entry] : history.map((p, i) => (i === idx ? entry : p));
    const monthLabel = `${MONTH_NAMES[month - 1]} ${year}`;

    try {
      await setDoc(doc(db, 'users', clientUid), { subscription: { history: newHistory } }, { merge: true });
      const activityType = isNew ? 'subscription_created' : (paymentStatus === 'paid' ? 'subscription_marked_paid' : 'subscription_marked_unpaid');
      logActivity(activityType, { targetEmail: client.email, targetName: client.fullName, monthLabel, paymentStatus });
      showToast(`${monthLabel} subscription ${isNew ? 'created' : 'updated'} for ${client.fullName || client.email}`);
      return { ok: true };
    } catch (e) {
      showToast('Could not update subscription — check your connection');
      return { ok: false };
    }
  };

  // Removes one subscription period entirely - for a mistakenly logged
  // entry (wrong month, fat-fingered dates, etc.), not a normal part of
  // the renewal flow. Super Admin only.
  const deleteSubscriptionPeriod = async (clientUid, { month, year }) => {
    if (myRole !== 'superadmin') { showToast("You don't have permission to manage subscriptions"); return; }
    const client = approvedUsers.find((u) => u.id === clientUid);
    if (!client) { showToast('Client not found'); return; }
    const history = client.subscription?.history || [];
    const newHistory = history.filter((p) => !(p.month === month && p.year === year));
    const monthLabel = `${MONTH_NAMES[month - 1]} ${year}`;
    try {
      await setDoc(doc(db, 'users', clientUid), { subscription: { history: newHistory } }, { merge: true });
      logActivity('subscription_deleted', { targetEmail: client.email, targetName: client.fullName, monthLabel });
      showToast(`${monthLabel} subscription record deleted for ${client.fullName || client.email}`);
      return { ok: true };
    } catch (e) {
      showToast('Could not delete subscription record — check your connection');
      return { ok: false };
    }
  };

  // Anyone can edit their own; a manager can edit others' (Client limited to
  // Staff by the UI list they're given and by the Firestore rules).
  const updateUserProfile = async (uid, fields) => {
    const isSelf = uid === user.uid;
    if (!isSelf && !can(myRole, 'manageUserProfiles')) {
      showToast("You don't have permission to edit this profile");
      return;
    }
    try {
      const payload = {
        fullName: fields.fullName?.trim() || '',
        username: fields.username?.trim() || '',
        contactNumber: fields.contactNumber?.trim() || '',
        address: fields.address?.trim() || '',
      };
      // Only include photoDataUri when a new photo was actually picked, so
      // saving other fields never accidentally clears an existing photo.
      if (fields.photoDataUri !== undefined) payload.photoDataUri = fields.photoDataUri;
      await setDoc(doc(db, 'users', uid), payload, { merge: true });
      showToast('Profile updated');
    } catch (e) {
      showToast('Could not update profile — check your connection');
    }
  };

  // Firebase requires a recent sign-in before allowing a password change, so
  // we re-authenticate with the user's current password first - this also
  // doubles as confirming they actually know the current password before
  // letting them set a new one.
  const changePassword = async (currentPassword, newPassword) => {
    try {
      const credential = EmailAuthProvider.credential(user.email, currentPassword);
      await reauthenticateWithCredential(auth.currentUser, credential);
      await updatePassword(auth.currentUser, newPassword);
      showToast('Password updated');
      return { ok: true };
    } catch (e) {
      const msg = e?.code === 'auth/wrong-password' || e?.code === 'auth/invalid-credential'
        ? 'Current password is incorrect'
        : e?.code === 'auth/weak-password'
        ? 'New password should be at least 6 characters'
        : e?.code === 'auth/too-many-requests'
        ? 'Too many attempts — please wait a bit and try again'
        : 'Could not update password — check your connection';
      showToast(msg);
      return { ok: false, error: e };
    }
  };

  // Super Admin edits the platform default (shown at sign-in and to any
  // tenant without their own override). A Client Admin edits ONLY their own
  // tenant's branding doc - it can never affect the platform default or any
  // other Client Admin's portal.
  const brandingDocFor = (role) => (role === 'superadmin' ? 'branding' : 'branding_' + ownerId);

  // Shared plumbing for every branding field (logo, theme, font, custom
  // colors) - routes to the platform default doc for Super Admin, or the
  // caller's own tenant-scoped doc for a Client Admin.
  const updateBranding = async (fields, successMsg) => {
    if (!isManager) return;
    try {
      await setDoc(doc(db, 'config', brandingDocFor(myRole)), {
        ...fields, ...(myRole === 'superadmin' ? {} : { ownerId }),
      }, { merge: true });
      if (successMsg) showToast(successMsg);
    } catch (e) {
      showToast('Could not update branding — check your connection');
    }
  };

  const saveLogo = async (dataUri) => {
    await updateBranding(
      { logoDataUri: dataUri },
      myRole === 'superadmin' ? 'Logo updated for everyone' : 'Logo updated for your inventory portal'
    );
  };

  const resetLogo = async () => {
    await updateBranding({ logoDataUri: null }, 'Reverted to the default logo');
  };

  const setThemeKey = async (key) => {
    await updateBranding({ themeKey: key }, `Theme changed to ${THEMES[key]?.label || key}`);
  };

  const setFontKey = async (key) => {
    await updateBranding({ fontKey: key }, `Text format changed to ${FONT_PRESETS[key]?.label || key}`);
  };

  const setCustomInk = async (hex) => {
    await updateBranding({ customInk: hex }, 'Text color updated');
  };

  const setCustomPanelBg = async (hex) => {
    await updateBranding({ customPanelBg: hex }, 'Panel color updated');
  };

  const setCustomSidebarBg = async (hex) => {
    await updateBranding({ customSidebarBg: hex }, 'Sidebar color updated');
  };

  const resetCustomColors = async () => {
    await updateBranding({ customInk: null, customPanelBg: null, customSidebarBg: null }, 'Reverted to theme default colors');
  };

  const setAnimationTheme = async (key) => {
    await updateBranding({ animationTheme: key }, `Background theme changed to ${ANIMATION_THEMES[key]?.label || key}`);
  };


  // Data: seed once per tenant if empty, then subscribe to live Firestore
  // updates - every query below is filtered by `ownerId` so one Client
  // Admin's inventory, suppliers, movements, sales, and reports are never
  // visible to another tenant. Staff inherit their tenant's ownerId, so the
  // same filtered queries automatically give them exactly (and only) their
  // Client Admin's data - nothing more.
  useEffect(() => {
    if (!user || !myProfile?.approved || !ownerId) { setLoaded(false); return; }
    let unsubs = [];
    let cancelled = false;
    const categoriesDocId = 'categories_' + ownerId;
    const locationsDocId = 'locations_' + ownerId;

    (async () => {
      try {
        // Only the tenant owner (Client Admin / Super Admin) seeds their own
        // workspace - staff never trigger seeding, they just read it.
        if (isManager) {
          const itemsSnap = await getDocs(query(collection(db, 'items'), where('ownerId', '==', ownerId)));
          if (itemsSnap.empty) {
            const seed = seedItems().map((it) => ({ ...it, id: 'i' + Math.random().toString(36).slice(2, 9) }));
            await Promise.all(seed.map((it) => setDoc(doc(db, 'items', it.id), { ...it, ownerId, holderId: ownerId })));
            const moves = seedMovements(seed).map((m) => ({ ...m, id: 'm' + Math.random().toString(36).slice(2, 9) }));
            await Promise.all(moves.map((m) => setDoc(doc(db, 'movements', m.id), { ...m, ownerId })));
          }
          // No default suppliers, categories, or locations are seeded for
          // new tenants any more - everything starts genuinely empty, and
          // a Client Admin builds their own list from scratch.

          // Multi-shop migration: runs once per tenant, the first time this
          // feature is live for them. Every tenant needs at least one shop
          // to function, and every item/sale/movement/order/restock/
          // deliveryStatus doc that predates this feature needs a shopId
          // so it isn't orphaned. Gated on a flag stored on the owner's own
          // profile so it's skipped entirely (no extra reads) once done.
          try {
            const ownerProfileSnap = await getDoc(doc(db, 'users', ownerId));
            const alreadyMigrated = ownerProfileSnap.exists() && ownerProfileSnap.data().multiShopMigrated;
            if (!alreadyMigrated) {
              const shopsSnap = await getDocs(query(collection(db, 'shops'), where('ownerId', '==', ownerId)));
              let defaultShopId;
              if (shopsSnap.empty) {
                defaultShopId = 'shop' + Math.random().toString(36).slice(2, 9);
                await setDoc(doc(db, 'shops', defaultShopId), { id: defaultShopId, name: 'My Shop', ownerId, createdAt: Date.now() });
              } else {
                defaultShopId = shopsSnap.docs[0].id;
              }
              const shopScopedCollections = ['items', 'sales', 'movements', 'orders', 'restocks', 'deliveryStatus'];
              for (const collName of shopScopedCollections) {
                const snap = await getDocs(query(collection(db, collName), where('ownerId', '==', ownerId)));
                const toMigrate = snap.docs.filter((d) => !d.data().shopId);
                await Promise.all(toMigrate.map((d) => setDoc(doc(db, collName, d.id), { shopId: defaultShopId }, { merge: true })));
              }
              await setDoc(doc(db, 'users', ownerId), { multiShopMigrated: true }, { merge: true });
            }
          } catch (e) {
            console.error('Multi-shop migration error:', e);
          }
        }
      } catch (e) {
        console.error('Seeding error:', e);
      }

      if (cancelled) return;

      // Staff only ever see stock assigned to THEM (holderId) - never the
      // Client Admin's master inventory or another staff member's stock.
      // Managers see the whole tenant's items regardless of holder, since
      // they need full oversight to assign/edit/reclaim stock.
      const itemsQuery = isManager
        ? query(collection(db, 'items'), where('ownerId', '==', ownerId))
        : query(collection(db, 'items'), where('ownerId', '==', ownerId), where('holderId', '==', user.uid));
      unsubs.push(onSnapshot(itemsQuery, (snap) => {
        setItems(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
      }, logSnapErr('items')));
      unsubs.push(onSnapshot(query(collection(db, 'suppliers'), where('ownerId', '==', ownerId)), (snap) => {
        setSuppliers(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
      }, logSnapErr('suppliers')));
      unsubs.push(onSnapshot(doc(db, 'config', categoriesDocId), (d) => {
        setCategories(d.exists() ? (d.data().list || []) : []);
      }, logSnapErr('categories')));
      unsubs.push(onSnapshot(doc(db, 'config', locationsDocId), (d) => {
        setLocations(d.exists() ? (d.data().list || []) : []);
      }, logSnapErr('locations')));

      // Report-like data: only managers (Client + Super Admin) can read these under
      // the Firestore rules, so staff skip subscribing to avoid permission errors.
      if (isManager) {
        unsubs.push(onSnapshot(query(collection(db, 'movements'), where('ownerId', '==', ownerId)), (snap) => {
          setMovements(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
        }, logSnapErr('movements')));
        unsubs.push(onSnapshot(query(collection(db, 'deliveryStatus'), where('ownerId', '==', ownerId)), (snap) => {
          const map = {};
          snap.docs.forEach((d) => { map[d.id] = d.data(); });
          setDeliveryStatuses(map);
        }, logSnapErr('deliveryStatus')));
        // Super Admin has no sales report access at all per policy - skip
        // the subscription entirely rather than just hiding it in the UI.
        if (myRole !== 'superadmin') {
          unsubs.push(onSnapshot(query(collection(db, 'sales'), where('ownerId', '==', ownerId)), (snap) => {
            setSales(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
          }, logSnapErr('sales-manager')));
        } else {
          setSales([]);
        }
        unsubs.push(onSnapshot(query(collection(db, 'orders'), where('ownerId', '==', ownerId)), (snap) => {
          setOrders(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.orderDate - a.orderDate));
        }, logSnapErr('orders')));
        unsubs.push(onSnapshot(query(collection(db, 'restocks'), where('ownerId', '==', ownerId)), (snap) => {
          setRestocks(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.receivedAt - a.receivedAt));
        }, logSnapErr('restocks')));
        unsubs.push(onSnapshot(query(collection(db, 'shops'), where('ownerId', '==', ownerId)), (snap) => {
          const list = snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
          setShops(list);
          // Pick an active shop the first time shops load: the user's own
          // last-selected shop if it still exists, otherwise just the
          // first one. Only sets it once (never overrides an active
          // selection the user already made this session).
          setActiveShopId((prev) => {
            if (prev && list.some((s) => s.id === prev)) return prev;
            const preferred = myProfile?.activeShopId;
            if (preferred && list.some((s) => s.id === preferred)) return preferred;
            return list[0]?.id || null;
          });
        }, logSnapErr('shops')));
        // Super Admin monitors login activity platform-wide; a Client only
        // sees activity for their own tenant (themselves + their staff).
        const logsQuery = myRole === 'superadmin'
          ? collection(db, 'loginLogs')
          : query(collection(db, 'loginLogs'), where('ownerId', '==', ownerId));
        unsubs.push(onSnapshot(logsQuery, (snap) => {
          setLoginLogs(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
        }, logSnapErr('loginLogs')));
      } else {
        setMovements([]);
        setDeliveryStatuses({});
        setLoginLogs([]);
        setOrders([]);
        setRestocks([]);
        setShops([]);
        setActiveShopId(null);
        // Staff only ever see their own sales - the query itself (not just the
        // rule) scopes this, so there's no risk of over-fetching then hiding.
        unsubs.push(onSnapshot(query(collection(db, 'sales'), where('cashierId', '==', user.uid)), (snap) => {
          setSales(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
        }, logSnapErr('sales-staff')));
      }

      setLoaded(true);
    })();

    return () => { cancelled = true; unsubs.forEach((u) => u()); };
  }, [user, myProfile?.approved, isManager, ownerId, myRole]);

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 2400);
  };

  // Extends the same tenant-scoped, already-permissioned loginLogs
  // collection to cover the full activity vocabulary (not just login/
  // logout) - staff creation, inventory changes, price/markup changes,
  // sales, and report generation. One shared shape keeps Activity Log's
  // filters simple: every entry has {type, meta, uid, email, timestamp,
  // ownerId}.
  const logActivity = async (type, meta = {}) => {
    if (!ownerId || !user) return;
    try {
      const logId = 'l' + Math.random().toString(36).slice(2, 9);
      await setDoc(doc(db, 'loginLogs', logId), {
        uid: user.uid, email: user.email || '', type, meta, timestamp: Date.now(), ownerId,
      });
    } catch (e) {
      console.error('Activity log error:', e);
    }
  };

  const saveItem = async (draft) => {
    if (!can(myRole, 'editInventory')) { showToast("You don't have permission to edit inventory"); return; }
    const isNew = !draft.id;
    const id = draft.id || ('i' + Math.random().toString(36).slice(2, 9));
    const holderId = draft.holderId || ownerId;
    const baseUnitName = (draft.baseUnitName || 'Piece').trim() || 'Piece';
    // Base Cost is genuinely optional - stored as null (not 0) when left
    // blank, so it's clearly distinguished from "cost is actually zero"
    // and so Markup correctly has nothing to calculate rather than
    // showing a misleading "full price = markup" number anywhere else
    // that reads this later.
    const unitCost = draft.unitCost === '' || draft.unitCost == null ? null : Math.max(0, Number(draft.unitCost) || 0);
    // Selling Price is required and typed directly; Markup is only ever a
    // derived readout (Selling Price - Base Cost), never stored as its
    // own field.
    const sellingPrice = Math.max(0, Number(draft.sellingPrice) || 0);
    const units = (draft.units || [])
      .filter((u) => u.name && u.name.trim() && Number(u.factor) > 0)
      .map((u) => ({
        name: u.name.trim(), factor: Number(u.factor),
        cost: u.cost === '' || u.cost == null ? null : Math.max(0, Number(u.cost) || 0),
        price: Math.max(0, Number(u.price) || 0),
      }));
    // The physical, discrete stock count at every unit level (e.g. 9 Packs
    // + 19 loose Pieces) is what actually gets stored and what POS
    // deduction cascades against - `quantity` below is just the derived
    // total in base-unit terms, kept for every other part of the app that
    // reads a single number.
    const unitStock = { [baseUnitName]: Math.max(0, Number(draft.baseUnitStock) || 0) };
    units.forEach((u) => { unitStock[u.name] = Math.max(0, Number((draft.units.find((x) => x.name === u.name) || {}).stock) || 0); });
    const quantity = Object.entries(unitStock).reduce((sum, [name, count]) => {
      const factor = name === baseUnitName ? 1 : (units.find((u) => u.name === name)?.factor || 1);
      return sum + count * factor;
    }, 0);
    const defaultSellingUnit = draft.defaultSellingUnit && (draft.defaultSellingUnit === baseUnitName || units.some((u) => u.name === draft.defaultSellingUnit))
      ? draft.defaultSellingUnit : baseUnitName;
    const reorderPoint = Math.max(0, Number(draft.reorderPoint) || 0);
    const { percent: markupValue } = computeMarkupFromPrices(unitCost || 0, sellingPrice);
    const markupType = 'percent';
    const previous = isNew ? null : items.find((i) => i.id === id);
    // Auto-assign a barcode the first time an item is created; preserved
    // as-is on every later edit (never regenerated for an existing item).
    const barcode = isNew ? (draft.barcode || generateBarcodeValue()) : (draft.barcode || previous?.barcode || generateBarcodeValue());
    // New items belong to whichever shop is currently active; editing an
    // existing item never changes which shop it belongs to.
    const shopId = isNew ? (draft.shopId || activeShopId) : (previous?.shopId ?? draft.shopId ?? activeShopId);
    try {
      await setDoc(doc(db, 'items', id), { ...draft, id, ownerId, holderId, quantity, reorderPoint, unitCost, sellingPrice, markupType, markupValue, barcode, baseUnitName, units, unitStock, shopId, defaultSellingUnit });
      if (isNew) {
        playAddSound();
        logActivity('inventory_added', { itemSku: draft.sku, itemName: draft.name });
      } else if (previous && previous.unitCost !== unitCost) {
        logActivity('price_changed', { itemSku: draft.sku, oldCost: previous.unitCost, newCost: unitCost });
      } else {
        logActivity('inventory_edited', { itemSku: draft.sku, itemName: draft.name });
      }
      showToast(draft.id ? `Updated ${draft.sku}` : `Added ${draft.sku} to the manifest`);
    } catch (e) {
      showToast('Could not save item — check your connection');
    }
    setItemModal(null);
  };

  const deleteItem = async (id) => {
    if (!can(myRole, 'deleteInventory')) { showToast("You don't have permission to delete inventory"); return; }
    const it = items.find((i) => i.id === id);
    try {
      await deleteDoc(doc(db, 'items', id));
      const related = movements.filter((m) => m.itemId === id);
      await Promise.all(related.map((m) => deleteDoc(doc(db, 'movements', m.id))));
      try { await deleteDoc(doc(db, 'deliveryStatus', id)); } catch {}
      showToast(`Removed ${it?.sku || 'item'} from the manifest`);
    } catch (e) {
      showToast('Could not remove item — check your connection');
    }
    setConfirmModal(null);
  };

  // Transfers stock out of the Client Admin's own master inventory into a
  // specific staff member's own separate inventory (a real stock movement,
  // logged on both sides) - or, if that staff member already has their own
  // copy of this item (tracked via sourceItemId), tops it up instead of
  // creating a duplicate line. The staff member's copy gets its own
  // independent quantity and starts with no markup - they set their own
  // from there.
  // Assigns a whole batch of items to one staff member in a single action -
  // each line gets its own quantity/base cost, transferred out of the
  // admin's own stock and into (or topped up in) that staff member's own
  // separate inventory, with movements logged on both sides for every line.
  const assignInventoryToStaff = async (staffUid, lines) => {
    if (!can(myRole, 'editInventory')) { showToast("You don't have permission to assign inventory"); return; }
    const staff = approvedUsers.find((u) => u.id === staffUid);
    if (!staff || !lines || lines.length === 0) { showToast('Pick a staff member and at least one item'); return; }

    const now = Date.now();
    let successCount = 0;
    const failedSkus = [];

    for (const line of lines) {
      const source = items.find((i) => i.id === line.itemId);
      const qty = Math.max(1, Number(line.quantity) || 0);
      if (!source || qty > source.quantity) {
        failedSkus.push(source?.sku || line.itemId);
        continue;
      }
      const cost = Math.max(0, Number(line.unitCost) || 0) || source.unitCost;
      const existing = items.find((i) => i.holderId === staffUid && i.sourceItemId === source.id);
      // Assigning to staff deducts from the source item's base unit, same
      // as manual Issue - reuses the same break-open cascade so the
      // discrete per-unit breakdown (Packs/Boxes/etc.) stays accurate
      // instead of silently drifting from the new total.
      const sourceBaseUnitName = source.baseUnitName || 'Piece';
      const sourceUnits = getItemUnits(source);
      const { newStock: sourceNewStock } = cascadeDeductUnit(getUnitCounts(source), sourceUnits, sourceBaseUnitName, qty);

      try {
        await setDoc(doc(db, 'items', source.id), { ...source, quantity: source.quantity - qty, unitStock: sourceNewStock });

        let staffItemId;
        if (existing) {
          staffItemId = existing.id;
          await setDoc(doc(db, 'items', existing.id), {
            ...existing, quantity: existing.quantity + qty, unitCost: cost,
            sellingPrice: computeSellingPrice(cost, existing.markupType || 'percent', existing.markupValue || 0),
          });
        } else {
          staffItemId = 'i' + Math.random().toString(36).slice(2, 9);
          const markupType = 'percent';
          const markupValue = 0;
          await setDoc(doc(db, 'items', staffItemId), {
            id: staffItemId, ownerId, holderId: staffUid, sourceItemId: source.id,
            sku: source.sku, name: source.name, category: source.category, barcode: source.barcode || generateBarcodeValue(),
            quantity: qty, reorderPoint: source.reorderPoint, unitCost: cost,
            location: source.location, supplierIds: getSupplierIds(source),
            markupType, markupValue, sellingPrice: computeSellingPrice(cost, markupType, markupValue),
            shopId: source.shopId || null,
          });
        }

        const mvOut = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvOut), {
          id: mvOut, itemId: source.id, type: 'out', qty,
          reason: `Assigned to ${staff.fullName || staff.email}`, timestamp: now, ownerId, shopId: source.shopId || activeShopId || null,
        });
        const mvIn = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvIn), {
          id: mvIn, itemId: staffItemId, type: 'in', qty,
          reason: 'Received from Client Admin', timestamp: now, ownerId, shopId: source.shopId || activeShopId || null,
        });

        logActivity('inventory_assigned', { itemSku: source.sku, itemName: source.name, qty, targetEmail: staff.email });
        successCount++;
      } catch (e) {
        failedSkus.push(source.sku);
      }
    }

    if (successCount > 0) playAddSound();
    if (failedSkus.length === 0) {
      showToast(`Assigned ${successCount} item${successCount === 1 ? '' : 's'} to ${staff.fullName || staff.email}`);
    } else {
      showToast(`Assigned ${successCount} item(s); couldn't assign: ${failedSkus.join(', ')}`);
    }
    setAssignModal(null);
  };

  // Staff can only ever touch the selling price on their OWN assigned
  // items - base cost, quantity, SKU, and everything else stays
  // admin-controlled. Also usable by a manager adjusting price directly,
  // since it's just a subset of what saveItem already allows them.
  const updateMarkup = async (item, sellingPriceInput) => {
    const isOwnItem = item.holderId === user.uid;
    if (!isOwnItem && !can(myRole, 'editInventory')) {
      showToast("You don't have permission to edit this item");
      return;
    }
    const sellingPrice = Math.max(0, Number(sellingPriceInput) || 0);
    const { percent: markupValue } = computeMarkupFromPrices(item.unitCost, sellingPrice);
    const markupType = 'percent';
    try {
      await setDoc(doc(db, 'items', item.id), { markupType, markupValue, sellingPrice }, { merge: true });
      logActivity('markup_changed', { itemSku: item.sku, itemName: item.name, markupType, markupValue });
      showToast(`Price updated for ${item.sku}`);
    } catch (e) {
      showToast('Could not update price — check your connection');
    }
    setMarkupModal(null);
  };

  // The inverse of assignInventoryToStaff: moves stock OUT of a staff
  // member's own inventory and back INTO the Client Admin's own inventory
  // (matched via sourceItemId, the same link assignInventoryToStaff sets
  // up). Usable by the staff member themselves (returning their own stock)
  // or by a Client Admin pulling stock back from a staff member directly.
  const returnInventoryToAdmin = async (staffItem, quantityInput) => {
    const isOwnItem = staffItem.holderId === user.uid;
    const isManagerCaller = can(myRole, 'editInventory');
    if (!isOwnItem && !isManagerCaller) {
      showToast("You don't have permission to return this item");
      return;
    }
    const qty = Math.max(1, Number(quantityInput) || 0);
    if (qty > staffItem.quantity) { showToast(`Only ${staffItem.quantity} available to return`); return; }

    // Only a manager (who already has full write access across the whole
    // tenant) can credit the admin's own item in the same action - a
    // staff-initiated return only ever touches their OWN held item
    // (already within their existing quantity permission), never writes to
    // someone else's inventory doc. If a Client Admin wants to formally
    // receive stock back, they use this same action themselves.
    const adminItem = (isManagerCaller && staffItem.sourceItemId)
      ? items.find((i) => i.id === staffItem.sourceItemId)
      : null;
    const now = Date.now();
    const staffUser = approvedUsers.find((u) => u.id === staffItem.holderId);
    const staffLabel = isOwnItem ? (user.email || 'you') : (staffUser?.fullName || staffUser?.email || 'staff');

    try {
      // Never delete the doc here (delete stays manager-only under current
      // rules) - just reduce to 0. The admin can clean up a zero-quantity
      // item manually if they want to.
      const remaining = Math.max(0, staffItem.quantity - qty);
      // Reducing the staff item's stock reuses the break-open cascade
      // (same as any other "issue" of stock), and crediting it back to the
      // admin's own item simply adds loose stock at its base unit level -
      // same pattern as manual Receive/Issue and staff assignment above.
      const staffBaseUnitName = staffItem.baseUnitName || 'Piece';
      const staffUnits = getItemUnits(staffItem);
      const { newStock: staffNewStock } = cascadeDeductUnit(getUnitCounts(staffItem), staffUnits, staffBaseUnitName, qty);
      await setDoc(doc(db, 'items', staffItem.id), { ...staffItem, quantity: remaining, unitStock: staffNewStock });

      if (adminItem) {
        const adminBaseUnitName = adminItem.baseUnitName || 'Piece';
        const adminCounts = getUnitCounts(adminItem);
        const adminNewStock = { ...adminCounts, [adminBaseUnitName]: (adminCounts[adminBaseUnitName] || 0) + qty };
        await setDoc(doc(db, 'items', adminItem.id), { ...adminItem, quantity: adminItem.quantity + qty, unitStock: adminNewStock });
      }

      const mvOut = 'm' + Math.random().toString(36).slice(2, 9);
      await setDoc(doc(db, 'movements', mvOut), {
        id: mvOut, itemId: staffItem.id, type: 'out', qty,
        reason: `Returned by ${staffLabel}`, timestamp: now, ownerId, shopId: staffItem.shopId || activeShopId || null,
      });
      if (adminItem) {
        const mvIn = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvIn), {
          id: mvIn, itemId: adminItem.id, type: 'in', qty,
          reason: `Returned by ${staffLabel}`, timestamp: now, ownerId, shopId: adminItem.shopId || activeShopId || null,
        });
      }

      logActivity('inventory_returned', { itemSku: staffItem.sku, itemName: staffItem.name, qty, byEmail: isOwnItem ? user.email : staffUser?.email });
      showToast(`Returned ${qty} × ${staffItem.sku}${adminItem ? ' to your inventory' : ''}`);
    } catch (e) {
      showToast('Could not process return — check your connection');
    }
    setReturnModal(null);
  };

  const saveSupplier = async (draft) => {
    if (!can(myRole, 'manageSuppliers')) { showToast("You don't have permission to manage suppliers"); return; }
    const id = draft.id || ('s' + Math.random().toString(36).slice(2, 9));
    const leadTimeDays = Math.max(0, Number(draft.leadTimeDays) || 0);
    try {
      await setDoc(doc(db, 'suppliers', id), { ...draft, id, ownerId, leadTimeDays });
      if (!draft.id) playAddSound();
      showToast(draft.id ? `Updated ${draft.name}` : `Added ${draft.name} to suppliers`);
    } catch (e) {
      showToast('Could not save supplier — check your connection');
    }
    setSupplierModal(null);
  };

  const deleteSupplier = async (id) => {
    if (!can(myRole, 'manageSuppliers')) { showToast("You don't have permission to manage suppliers"); return; }
    const s = suppliers.find((x) => x.id === id);
    try {
      await deleteDoc(doc(db, 'suppliers', id));
      const affected = items.filter((it) => getSupplierIds(it).includes(id));
      await Promise.all(affected.map((it) => setDoc(doc(db, 'items', it.id), {
        ...it, supplierIds: getSupplierIds(it).filter((sid) => sid !== id),
      })));
      showToast(`Removed ${s?.name || 'supplier'}`);
    } catch (e) {
      showToast('Could not remove supplier — check your connection');
    }
    setConfirmModal(null);
  };

  const addCategory = async (name) => {
    if (!can(myRole, 'manageCategories')) { showToast("You don't have permission to manage categories"); return; }
    const trimmed = name.trim();
    if (!trimmed) return;
    if (categories.some((c) => c.toLowerCase() === trimmed.toLowerCase())) {
      showToast(`"${trimmed}" already exists`);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'categories_' + ownerId), { list: [...categories, trimmed], ownerId });
      playAddSound();
      showToast(`Added category "${trimmed}"`);
    } catch (e) {
      showToast('Could not add category — check your connection');
    }
  };

  const deleteCategory = async (name) => {
    if (!can(myRole, 'manageCategories')) { showToast("You don't have permission to manage categories"); return; }
    const inUse = items.filter((it) => it.category === name).length;
    if (inUse > 0) {
      showToast(`Can't remove "${name}" — ${inUse} item${inUse === 1 ? '' : 's'} still use it`);
      setConfirmModal(null);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'categories_' + ownerId), { list: categories.filter((c) => c !== name), ownerId });
      showToast(`Removed category "${name}"`);
    } catch (e) {
      showToast('Could not remove category — check your connection');
    }
    setConfirmModal(null);
  };

  const updateDeliveryStatus = async (itemId, status, note, orderDate) => {
    if (!can(myRole, 'viewReports')) { showToast("You don't have permission to update delivery status"); return; }
    const relatedItem = items.find((i) => i.id === itemId);
    try {
      await setDoc(doc(db, 'deliveryStatus', itemId), {
        status, note: note || '', orderDate: orderDate || null, updatedAt: Date.now(), ownerId,
        shopId: relatedItem?.shopId || activeShopId || null,
      });
      showToast(`Delivery status set to "${status}"`);
    } catch (e) {
      showToast('Could not update delivery status — check your connection');
    }
    setDeliveryStatusModal(null);
  };

  const clearDeliveryStatus = async (itemId) => {
    if (!can(myRole, 'viewReports')) { showToast("You don't have permission to update delivery status"); return; }
    try {
      await deleteDoc(doc(db, 'deliveryStatus', itemId));
      showToast('Reverted to automatic status');
    } catch (e) {
      showToast('Could not clear delivery status — check your connection');
    }
    setDeliveryStatusModal(null);
  };

  const addLocation = async (name) => {
    if (!can(myRole, 'manageLocations')) { showToast("You don't have permission to manage locations"); return; }
    const trimmed = name.trim();
    if (!trimmed) return;
    if (locations.some((l) => l.toLowerCase() === trimmed.toLowerCase())) {
      showToast(`"${trimmed}" already exists`);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'locations_' + ownerId), { list: [...locations, trimmed], ownerId });
      playAddSound();
      showToast(`Added location "${trimmed}"`);
    } catch (e) {
      showToast('Could not add location — check your connection');
    }
  };

  const deleteLocation = async (name) => {
    if (!can(myRole, 'manageLocations')) { showToast("You don't have permission to manage locations"); return; }
    const inUse = items.filter((it) => it.location === name).length;
    if (inUse > 0) {
      showToast(`Can't remove "${name}" — ${inUse} item${inUse === 1 ? '' : 's'} still use it`);
      setConfirmModal(null);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'locations_' + ownerId), { list: locations.filter((l) => l !== name), ownerId });
      showToast(`Removed location "${name}"`);
    } catch (e) {
      showToast('Could not remove location — check your connection');
    }
    setConfirmModal(null);
  };

  const recordMovement = async (itemId, type, qty, reason) => {
    if (type === 'in' && !can(myRole, 'stockReceive')) { showToast("You don't have permission to receive stock"); return; }
    if (type === 'out' && !can(myRole, 'stockIssue')) { showToast("You don't have permission to issue stock"); return; }
    const item = items.find((i) => i.id === itemId);
    if (!item) return;
    const delta = type === 'in' ? qty : -qty;
    const newQty = Math.max(0, item.quantity + delta);
    // Manual receive/issue always happens in the item's base unit (there's
    // no unit picker on this flow). Receiving simply adds loose stock at
    // the base level. Issuing more than what's currently loose reuses the
    // same break-open cascade as POS, so the discrete per-unit breakdown
    // never drifts out of sync with the new total.
    const baseUnitName = item.baseUnitName || 'Piece';
    const units = getItemUnits(item);
    const counts = getUnitCounts(item);
    let unitStock;
    if (type === 'in') {
      unitStock = { ...counts, [baseUnitName]: (counts[baseUnitName] || 0) + qty };
    } else {
      const result = cascadeDeductUnit(counts, units, baseUnitName, qty);
      unitStock = result.newStock; // shortfall (if any) is already reflected in newQty via Math.max(0, ...) above
    }
    const mvId = 'm' + Math.random().toString(36).slice(2, 9);
    try {
      await setDoc(doc(db, 'items', itemId), { ...item, quantity: newQty, unitStock });
      await setDoc(doc(db, 'movements', mvId), {
        id: mvId, itemId, type, qty,
        reason: reason || (type === 'in' ? 'Stock received' : 'Stock issued'),
        timestamp: Date.now(), ownerId, shopId: item.shopId || activeShopId || null,
      });
      showToast(`${type === 'in' ? 'Received' : 'Issued'} ${qty} × ${item.sku}`);
    } catch (e) {
      showToast('Could not record movement — check your connection');
    }
    setMoveModal(null);
  };

  // Order / Restock module: unlike a formal Purchase Order (Stock
  // Management -> Orders, which has a Pending/Received/Cancelled
  // lifecycle and a required supplier), every restock record here
  // represents inventory that has ALREADY been received - there's no
  // status to track, and a supplier is entirely optional. Submitting one
  // both logs a dedicated, searchable restock record AND updates the
  // item's stock immediately, same permission gate as a manual Receive.
  const createRestock = async ({ itemId, quantity, unitName, unitCost, supplierId, notes }) => {
    if (!can(myRole, 'stockReceive')) { showToast("You don't have permission to receive stock"); return; }
    const item = items.find((i) => i.id === itemId);
    const qty = Math.max(0, Number(quantity) || 0);
    if (!item || qty <= 0) { showToast('Pick an item and a quantity greater than zero'); return; }

    const units = getItemUnits(item);
    const unit = units.find((u) => u.name === unitName) || units[0];
    const counts = getUnitCounts(item);
    const newStock = { ...counts, [unit.name]: (counts[unit.name] || 0) + qty };
    const newQuantity = totalBaseUnits(newStock, units);
    const cost = Math.max(0, Number(unitCost) || 0) || (item.unitCost ?? 0);
    const supplier = supplierId ? suppliers.find((s) => s.id === supplierId) : null;
    const now = Date.now();
    const restockId = 'rs' + Math.random().toString(36).slice(2, 9);

    try {
      await setDoc(doc(db, 'items', itemId), { ...item, quantity: newQuantity, unitStock: newStock });
      await setDoc(doc(db, 'restocks', restockId), {
        id: restockId, itemId, itemSku: item.sku, itemName: item.name,
        quantity: qty, unitName: unit.name, unitCost: cost,
        supplierId: supplier?.id || null, supplierName: supplier?.name || null,
        receivedAt: now, receivedBy: user.uid, receivedByEmail: user.email || '',
        receivedByUsername: myProfile?.username || '', notes: notes || '', ownerId,
        shopId: item.shopId || activeShopId || null,
      });
      const mvId = 'm' + Math.random().toString(36).slice(2, 9);
      await setDoc(doc(db, 'movements', mvId), {
        id: mvId, itemId, type: 'in', qty: qty * unit.factor,
        reason: `Restock${supplier ? ` from ${supplier.name}` : ''}${unit.name !== (item.baseUnitName || 'Piece') ? ` (${qty} ${unit.name})` : ''}`,
        timestamp: now, ownerId, shopId: item.shopId || activeShopId || null,
      });
      logActivity('restock_received', { itemSku: item.sku, itemName: item.name, quantity: qty, unitName: unit.name, supplierName: supplier?.name || 'none' });
      showToast(`Received ${qty} ${unit.name}${qty === 1 ? '' : 's'} of ${item.sku}`);
      setRestockModal(false);
    } catch (e) {
      showToast('Could not record restock — check your connection');
    }
  };

  const completeSale = async (cartLines, amountReceived) => {
    if (cartLines.length === 0) return;

    // Simulate the cascading break-open deduction for every affected item
    // BEFORE writing anything, so a sale either fully succeeds or fully
    // fails - never partially deducts some lines and not others. Cart
    // lines are grouped by item since the same item can appear multiple
    // times in one sale in different units (e.g. 2 Pieces AND 1 Pack of
    // the same product), and each line has to see the effect of the ones
    // before it.
    const finalStockByItem = {}; // itemId -> { units, newStock, newQuantity }
    for (const line of cartLines) {
      const item = items.find((i) => i.id === line.itemId);
      if (!item) { showToast('An item in this sale no longer exists'); return; }
      const units = getItemUnits(item);
      const current = finalStockByItem[item.id]?.newStock || getUnitCounts(item);
      const sellUnitName = line.unitName || item.baseUnitName || 'Piece';
      const { newStock, shortfall } = cascadeDeductUnit(current, units, sellUnitName, line.qty);
      if (shortfall > 0) {
        showToast(`Not enough stock for ${item.sku} (short ${shortfall} ${sellUnitName}${shortfall === 1 ? '' : 's'} even after opening larger units)`);
        return;
      }
      finalStockByItem[item.id] = { units, newStock, newQuantity: totalBaseUnits(newStock, units) };
    }

    const receiptNo = 'R' + Date.now().toString(36).toUpperCase();
    const now = Date.now();
    const saleLines = cartLines.map((line) => {
      const item = items.find((i) => i.id === line.itemId);
      const factor = line.factor ?? 1;
      // unitPrice/unitCost here are already per SOLD unit (e.g. per Box/Case,
      // not per Piece) - both come from whichever unit was selected in POS,
      // since each unit now has its own independently-set cost (a Pack can
      // genuinely cost less per piece than buying loose) rather than always
      // being derived from the base cost.
      const soldUnit = getItemUnits(item).find((u) => u.name === (line.unitName || item.baseUnitName));
      const price = line.unitPrice ?? (item.sellingPrice ?? item.unitCost);
      const lineCost = (soldUnit?.cost ?? item.unitCost) * (soldUnit ? 1 : factor); // fallback path still scales by factor if the unit lookup somehow fails
      return {
        itemId: item.id, sku: item.sku, name: item.name,
        qty: line.qty, unitName: line.unitName || item.baseUnitName || 'Piece', factor,
        unitPrice: price, unitCost: lineCost,
        lineTotal: price * line.qty, lineProfit: (price - lineCost) * line.qty,
      };
    });
    const subtotal = saleLines.reduce((s, l) => s + l.lineTotal, 0);
    const totalCost = saleLines.reduce((s, l) => s + l.unitCost * l.qty, 0);
    const totalProfit = saleLines.reduce((s, l) => s + l.lineProfit, 0);
    const total = subtotal;
    // Bill (amount received) is optional at the data layer, even though the
    // POS UI requires it before allowing checkout - keeps this function
    // safe to call from anywhere else in the future without a hard
    // dependency on cash-handling fields.
    const received = amountReceived != null && amountReceived !== '' ? Number(amountReceived) : null;
    const change = received != null ? Math.max(0, received - total) : null;
    const sale = {
      id: 's' + Math.random().toString(36).slice(2, 9), receiptNo, timestamp: now, items: saleLines,
      subtotal, total, totalCost, totalProfit, amountReceived: received, change,
      cashierId: user.uid, cashierEmail: user.email || '', cashierUsername: myProfile?.username || '', ownerId,
      shopId: activeShopId || null,
    };

    try {
      // One write per affected item (not per cart line), carrying the
      // final post-cascade stock breakdown plus the recomputed total.
      await Promise.all(Object.entries(finalStockByItem).map(([itemId, { newStock, newQuantity }]) => {
        const item = items.find((i) => i.id === itemId);
        return setDoc(doc(db, 'items', itemId), { ...item, quantity: newQuantity, unitStock: newStock });
      }));
      await Promise.all(cartLines.map((line) => {
        const mvId = 'm' + Math.random().toString(36).slice(2, 9);
        const baseQty = line.qty * (line.factor ?? 1);
        // Movements are always recorded in the item's base unit, same as
        // every other stock-in/stock-out path in the app, regardless of
        // which unit was actually sold at the register.
        return setDoc(doc(db, 'movements', mvId), {
          id: mvId, itemId: line.itemId, type: 'out', qty: baseQty,
          reason: `Sale ${receiptNo}${line.unitName && line.unitName !== 'Piece' ? ` (${line.qty} ${line.unitName})` : ''}`, timestamp: now, ownerId,
          shopId: activeShopId || null,
        });
      }));
      await setDoc(doc(db, 'sales', sale.id), sale);
      playSaleSound();
      logActivity('sale_completed', { receiptNo, total, itemCount: saleLines.length });
      showToast(`Sale ${receiptNo} recorded — ${currency(total)}`);
      return sale;
    } catch (e) {
      showToast('Could not complete sale — check your connection');
    }
  };

  const cancelSale = async (sale) => {
    if (!can(myRole, 'cancelSales')) { showToast("You don't have permission to cancel sales"); return; }
    if (sale.cancelled) { showToast('This sale is already cancelled'); return; }
    const now = Date.now();
    try {
      await Promise.all(sale.items.map((line) => {
        const item = items.find((i) => i.id === line.itemId);
        if (!item) return Promise.resolve(); // item was deleted since the sale; nothing to restore
        return setDoc(doc(db, 'items', line.itemId), { ...item, quantity: item.quantity + line.qty });
      }));
      await Promise.all(sale.items.map((line) => {
        const mvId = 'm' + Math.random().toString(36).slice(2, 9);
        return setDoc(doc(db, 'movements', mvId), {
          id: mvId, itemId: line.itemId, type: 'in', qty: line.qty,
          reason: `Sale ${sale.receiptNo} cancelled`, timestamp: now, ownerId,
        });
      }));
      await setDoc(doc(db, 'sales', sale.id), {
        cancelled: true, cancelledAt: now, cancelledBy: user.email || user.uid,
      }, { merge: true });
      showToast(`Sale ${sale.receiptNo} cancelled — stock restored`);
    } catch (e) {
      showToast('Could not cancel sale — check your connection');
    }
    setConfirmModal(null);
  };

  // Client Admin only (not Super Admin, who has no sales access at all) -
  // permanently removes an already-cancelled sale record from the table.
  // Only ever allowed on sales that are already cancelled, since a live
  // sale should go through Cancel first (which restores stock) rather
  // than being deleted outright.
  const deleteSale = async (sale) => {
    if (myRole !== 'client') { showToast("You don't have permission to delete sales"); return; }
    if (!sale.cancelled) { showToast('Only cancelled sales can be deleted'); return; }
    try {
      await deleteDoc(doc(db, 'sales', sale.id));
      showToast(`Sale ${sale.receiptNo} deleted`);
    } catch (e) {
      showToast('Could not delete sale — check your connection');
    }
    setConfirmModal(null);
  };

  const saveOrder = async (draft) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage orders"); return; }
    const item = items.find((i) => i.id === draft.itemId);
    const supplier = suppliers.find((s) => s.id === draft.supplierId);
    if (!item || !supplier) { showToast('Pick an item and one of its suppliers'); return; }
    const quantity = Math.max(1, Number(draft.quantity) || 0);
    const unitCost = Math.max(0, Number(draft.unitCost) || 0);
    const now = Date.now();
    const id = 'o' + Math.random().toString(36).slice(2, 9);
    const order = {
      id, ownerId,
      itemId: item.id, itemSku: item.sku, itemName: item.name,
      supplierId: supplier.id, supplierName: supplier.name,
      quantity, unitCost, totalCost: quantity * unitCost,
      status: 'pending',
      orderDate: now,
      expectedDate: now + (supplier.leadTimeDays || 0) * DAY_MS,
      receivedDate: null,
      notes: (draft.notes || '').trim(),
      createdBy: user.uid, createdByEmail: user.email || '',
      shopId: item.shopId || activeShopId || null,
    };
    try {
      await setDoc(doc(db, 'orders', id), order);
      playAddSound();
      showToast(`Order placed with ${supplier.name}`);
    } catch (e) {
      showToast('Could not place order — check your connection');
    }
    setOrderModal(null);
  };

  const receiveOrder = async (order) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage orders"); return; }
    if (order.status !== 'pending') { showToast(`This order is already ${order.status}`); return; }
    const item = items.find((i) => i.id === order.itemId);
    const now = Date.now();
    try {
      if (item) {
        await setDoc(doc(db, 'items', item.id), { ...item, quantity: item.quantity + order.quantity });
        const mvId = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvId), {
          id: mvId, itemId: item.id, type: 'in', qty: order.quantity,
          reason: `Order received from ${order.supplierName}`, timestamp: now, ownerId,
          shopId: item.shopId || activeShopId || null,
        });
      }
      await setDoc(doc(db, 'orders', order.id), { status: 'received', receivedDate: now }, { merge: true });
      showToast(item ? `Order received — ${order.quantity} × ${order.itemSku} added to stock` : 'Order marked received');
    } catch (e) {
      showToast('Could not mark order received — check your connection');
    }
  };

  const cancelOrder = async (order) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage orders"); return; }
    if (order.status !== 'pending') { showToast(`This order is already ${order.status}`); return; }
    try {
      await setDoc(doc(db, 'orders', order.id), {
        status: 'cancelled', cancelledAt: Date.now(), cancelledBy: user.email || user.uid,
      }, { merge: true });
      showToast(`Order for ${order.itemSku} cancelled`);
    } catch (e) {
      showToast('Could not cancel order — check your connection');
    }
    setConfirmModal(null);
  };

  // Staff's `items` state is already query-scoped to just their own holderId
  // (see the data-loading effect), so it needs no further filtering here.
  // A manager's `items` state includes the WHOLE tenant (their own master
  // inventory + everything assigned to every staff member) - "my own
  // inventory" for a manager means just the items they still personally
  // hold, i.e. haven't assigned out. Legacy items from before this feature
  // (no holderId yet) default to counting as the admin's own.
  const myOwnItems = useMemo(() => {
    if (myRole === 'staff') return items; // staff aren't shop-scoped - they only ever see their own assigned items
    const ownItems = items.filter((it) => !it.holderId || it.holderId === ownerId);
    if (!activeShopId) return ownItems;
    // Items that predate this feature (no shopId yet) fall back to
    // matching the active shop too, so nothing silently disappears in the
    // brief window before the one-time migration finishes tagging them.
    return ownItems.filter((it) => !it.shopId || it.shopId === activeShopId);
  }, [items, myRole, ownerId, activeShopId]);

  // Shop-scoped views of sales/movements/orders/restocks, same reasoning
  // as myOwnItems above - a manager switching shops should only see that
  // shop's own sales history, reports, profit, restock records, etc.
  // Staff aren't shop-scoped, so this doesn't affect their own sales view.
  const shopSales = useMemo(() => {
    if (!activeShopId) return sales;
    return sales.filter((s) => !s.shopId || s.shopId === activeShopId);
  }, [sales, activeShopId]);
  const shopMovements = useMemo(() => {
    if (!activeShopId) return movements;
    return movements.filter((m) => !m.shopId || m.shopId === activeShopId);
  }, [movements, activeShopId]);
  const shopOrders = useMemo(() => {
    if (!activeShopId) return orders;
    return orders.filter((o) => !o.shopId || o.shopId === activeShopId);
  }, [orders, activeShopId]);
  const shopRestocks = useMemo(() => {
    if (!activeShopId) return restocks;
    return restocks.filter((r) => !r.shopId || r.shopId === activeShopId);
  }, [restocks, activeShopId]);

  const switchShop = async (shopId) => {
    setActiveShopId(shopId);
    try {
      await setDoc(doc(db, 'users', user.uid), { activeShopId: shopId }, { merge: true });
    } catch (e) { /* non-critical preference save - the in-session switch above already applied */ }
  };

  const createShop = async (name) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage shops"); return; }
    const trimmed = (name || '').trim();
    if (!trimmed) return;
    const shopId = 'shop' + Math.random().toString(36).slice(2, 9);
    try {
      await setDoc(doc(db, 'shops', shopId), { id: shopId, name: trimmed, ownerId, createdAt: Date.now() });
      switchShop(shopId);
      showToast(`Created "${trimmed}"`);
    } catch (e) {
      showToast('Could not create shop — check your connection');
    }
  };

  const renameShop = async (shopId, name) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage shops"); return; }
    const trimmed = (name || '').trim();
    if (!trimmed) return;
    try {
      await setDoc(doc(db, 'shops', shopId), { name: trimmed }, { merge: true });
      showToast('Shop renamed');
    } catch (e) {
      showToast('Could not rename shop — check your connection');
    }
  };

  const deleteShop = async (shopId) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage shops"); return; }
    if (shops.length <= 1) { showToast('You need at least one shop'); return; }
    try {
      await deleteDoc(doc(db, 'shops', shopId));
      if (activeShopId === shopId) {
        const remaining = shops.find((s) => s.id !== shopId);
        if (remaining) switchShop(remaining.id);
      }
      showToast('Shop deleted. Its existing items/sales/records are kept, just no longer tagged to an active shop, and will need reassigning if you want them under a different one.');
    } catch (e) {
      showToast('Could not delete shop — check your connection');
    }
  };

  // Total value of stock currently OUT with staff (assigned, not sitting in
  // the admin's own inventory), broken down per staff member - managers
  // only, since it's derived from the whole-tenant `items` state they alone
  // have access to.
  const staffInventoryStats = useMemo(() => {
    if (myRole === 'staff') return { total: 0, byStaff: [] };
    const staffItems = items.filter((it) => it.holderId && it.holderId !== ownerId);
    const total = staffItems.reduce((s, it) => s + it.quantity * it.unitCost, 0);
    const byStaffMap = {};
    staffItems.forEach((it) => {
      if (!byStaffMap[it.holderId]) byStaffMap[it.holderId] = { staffUid: it.holderId, value: 0, skuCount: 0, units: 0 };
      byStaffMap[it.holderId].value += it.quantity * it.unitCost;
      byStaffMap[it.holderId].skuCount += 1;
      byStaffMap[it.holderId].units += it.quantity;
    });
    const byStaff = Object.values(byStaffMap)
      .map((s) => {
        const staffUser = approvedUsers.find((u) => u.id === s.staffUid);
        return { ...s, name: staffUser?.fullName || staffUser?.email || 'Unknown Staff' };
      })
      .sort((a, b) => b.value - a.value);
    return { total, byStaff };
  }, [items, ownerId, myRole, approvedUsers]);

  const filtered = useMemo(() => {
    let list = myOwnItems.filter((it) => {
      const matchesSearch =
        it.name.toLowerCase().includes(search.toLowerCase()) ||
        it.sku.toLowerCase().includes(search.toLowerCase());
      const matchesCat = categoryFilter === 'All' || it.category === categoryFilter;
      return matchesSearch && matchesCat;
    });
    list.sort((a, b) => {
      if (sortKey === 'name') return a.name.localeCompare(b.name);
      if (sortKey === 'qty') return b.quantity - a.quantity;
      if (sortKey === 'value') return b.quantity * b.unitCost - a.quantity * a.unitCost;
      if (sortKey === 'low') return (a.quantity - a.reorderPoint) - (b.quantity - b.reorderPoint);
      return 0;
    });
    return list;
  }, [myOwnItems, search, categoryFilter, sortKey]);

  const totals = useMemo(() => {
    const totalUnits = myOwnItems.reduce((s, i) => s + i.quantity, 0);
    const totalValue = myOwnItems.reduce((s, i) => s + i.quantity * i.unitCost, 0);
    const lowStock = myOwnItems.filter((i) => i.quantity <= i.reorderPoint);
    return { totalSkus: myOwnItems.length, totalUnits, totalValue, lowStock };
  }, [items]);

  const categoryData = useMemo(() => {
    return categories.map((cat) => ({
      category: cat.split(' ')[0],
      units: myOwnItems.filter((i) => i.category === cat).reduce((s, i) => s + i.quantity, 0),
    })).filter((c) => c.units > 0);
  }, [myOwnItems, categories]);

  // Profit is derived entirely from completed (non-cancelled) sales, which
  // already carry a cost/profit snapshot per line from the moment they were
  // rung up - so re-pricing an item later never rewrites history here.
  const profitStats = useMemo(() => {
    const completed = shopSales.filter((s) => !s.cancelled);
    const totalRevenue = completed.reduce((s, sale) => s + (sale.total ?? 0), 0);
    const totalCost = completed.reduce((s, sale) => s + (sale.totalCost ?? 0), 0);
    const totalProfit = completed.reduce((s, sale) => s + (sale.totalProfit ?? (sale.total ?? 0) - (sale.totalCost ?? 0)), 0);
    const margin = totalRevenue > 0 ? (totalProfit / totalRevenue) * 100 : 0;

    const byItem = {};
    completed.forEach((sale) => {
      (sale.items || []).forEach((line) => {
        if (!byItem[line.itemId]) byItem[line.itemId] = { itemId: line.itemId, sku: line.sku, name: line.name, qty: 0, profit: 0 };
        byItem[line.itemId].qty += line.qty;
        byItem[line.itemId].profit += line.lineProfit ?? ((line.unitPrice ?? 0) - (line.unitCost ?? 0)) * line.qty;
      });
    });
    const profitByItem = Object.values(byItem).sort((a, b) => b.profit - a.profit);

    const perSale = completed
      .slice(0, 8)
      .map((s) => ({
        id: s.id, receiptNo: s.receiptNo, timestamp: s.timestamp,
        revenue: s.total ?? 0, cost: s.totalCost ?? 0,
        profit: s.totalProfit ?? (s.total ?? 0) - (s.totalCost ?? 0),
      }));

    return { totalRevenue, totalCost, totalProfit, margin, profitByItem, perSale };
  }, [shopSales]);

  const filteredMovements = useMemo(() => {
    return shopMovements.filter((m) => {
      const item = items.find((i) => i.id === m.itemId);
      const matchesSearch =
        !histSearch ||
        (item && (item.sku.toLowerCase().includes(histSearch.toLowerCase()) || item.name.toLowerCase().includes(histSearch.toLowerCase()))) ||
        m.reason.toLowerCase().includes(histSearch.toLowerCase());
      const matchesType = histType === 'All' || m.type === histType.toLowerCase();
      const matchesItem = histItem === 'All' || m.itemId === histItem;
      return matchesSearch && matchesType && matchesItem;
    });
  }, [movements, items, histSearch, histType, histItem]);

  const deliveryRows = useMemo(() => {
    const rows = [];
    myOwnItems.forEach((it) => {
      getSupplierIds(it).forEach((sid) => {
        const supplier = suppliers.find((s) => s.id === sid);
        if (!supplier) return;
        const inbound = shopMovements
          .filter((m) => m.itemId === it.id && m.type === 'in')
          .sort((a, b) => b.timestamp - a.timestamp);
        const lastDelivery = inbound.length ? inbound[0].timestamp : null;
        const lastDeliveryQty = inbound.length ? inbound[0].qty : null;
        const expectedNext = lastDelivery ? lastDelivery + supplier.leadTimeDays * DAY_MS : null;
        const overdue = expectedNext && expectedNext < Date.now() && it.quantity <= it.reorderPoint;
        const autoStatus = it.quantity <= it.reorderPoint ? (overdue ? 'Delivery Overdue' : 'Reorder Now') : 'On Track';
        // A manual status override is set per-item (not per-supplier) - if an
        // item has more than one supplier, both rows share the same override.
        const override = deliveryStatuses[it.id];
        const status = override ? override.status : autoStatus;
        rows.push({
          item: it, supplier, lastDelivery, lastDeliveryQty, expectedNext, status, autoStatus,
          manual: !!override, note: override?.note || '', orderDate: override?.orderDate || null,
          log: inbound, // full delivery history for this item, most recent first
        });
      });
    });
    return rows;
  }, [myOwnItems, suppliers, shopMovements, deliveryStatuses]);

  const supplierMap = useMemo(() => Object.fromEntries(suppliers.map((s) => [s.id, s])), [suppliers]);

  // Global scanner support for stock receiving / stock counting / general
  // inventory updates: while browsing Inventory or Staff Inventory, a scan
  // jumps straight to that item's Receive/Issue movement modal instead of
  // requiring it to be found and clicked manually first. (POS has its own
  // scanner hook, scoped to adding items to the current sale instead.)
  const inventoryScanEnabled = view === 'inventory' || view === 'staffInventory';
  const handleInventoryScan = (code) => {
    const found = findItemByScan(items, code);
    if (found) {
      setMoveModal(found);
    } else {
      showToast(`No item matches scanned barcode ${code}`);
    }
  };
  useBarcodeScanner(handleInventoryScan, inventoryScanEnabled);

  if (!authChecked) {
    return (
      <div style={{ ...styles.wrap, alignItems: 'center', justifyContent: 'center', display: 'flex' }}>
        <style>{FONT_IMPORT}</style>
        <div style={{ fontFamily: "'Quicksand', sans-serif", color: 'var(--line)', letterSpacing: '0.08em' }}>
          LOADING…
        </div>
      </div>
    );
  }

  if (!user) {
    if (!introDone) {
      return (
        <IntroSplash
          logo={effectiveLogo}
          onFinish={() => {
            try { sessionStorage.setItem('stockit_intro_shown', '1'); } catch {}
            setIntroDone(true);
          }}
        />
      );
    }
    return <LoginScreen logo={effectiveLogo} theme={activeTheme} animationTheme={effectiveBranding.animationTheme} />;
  }

  if (!profileChecked) {
    return (
      <div style={{ ...styles.wrap, alignItems: 'center', justifyContent: 'center', display: 'flex' }}>
        <style>{FONT_IMPORT}</style>
        <div style={{ fontFamily: "'Quicksand', sans-serif", color: 'var(--line)', letterSpacing: '0.08em' }}>
          CHECKING YOUR ACCOUNT…
        </div>
      </div>
    );
  }

  if (!myProfile || !myProfile.approved) {
    return <PendingApprovalScreen email={user.email} missingProfile={!myProfile} animationTheme={effectiveBranding.animationTheme} onSignOut={handleSignOut} />;
  }

  if (accessPaused) {
    return <SubscriptionPausedScreen role={myRole} animationTheme={effectiveBranding.animationTheme} onSignOut={handleSignOut} />;
  }

  if (!loaded) {
    return (
      <div style={{ ...styles.wrap, alignItems: 'center', justifyContent: 'center', display: 'flex' }}>
        <style>{FONT_IMPORT}</style>
        <div style={{ fontFamily: "'Quicksand', sans-serif", color: 'var(--line)', letterSpacing: '0.08em' }}>
          LOADING MANIFEST…
        </div>
      </div>
    );
  }

  return (
    <div style={styles.wrap} className="depot-wrap">
      <style>{`
        ${FONT_IMPORT}
        ${RESPONSIVE_CSS}
        ${themeCssVars(activeTheme, activeFontFamily, effectiveBranding.customInk, effectiveBranding.customPanelBg, effectiveBranding.customSidebarBg)}
        * { box-sizing: border-box; }
        .depot-btn { cursor: pointer; border: none; font-family: var(--font-body); transition: all 0.15s ease; }
        .depot-btn:active { transform: translateY(1px); }
        .depot-row:hover { background: rgba(15,42,71,0.04); }
        .depot-input:focus, .depot-select:focus { outline: 2px solid var(--blueprint); outline-offset: 1px; }
        .depot-scroll::-webkit-scrollbar { width: 8px; height: 8px; }
        .depot-scroll::-webkit-scrollbar-thumb { background: var(--line-dim); border-radius: 4px; }
        @keyframes slideUp { from { opacity: 0; transform: translateY(8px);} to { opacity:1; transform:translateY(0);} }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @media print {
          .depot-sidebar, .depot-no-print { display: none !important; }
          .depot-main { padding: 0 !important; overflow: visible !important; }
          .depot-print-title { display: block !important; }
          body { background: #fff !important; }
          .barcode-print-only { display: block !important; }
          .barcode-browse-grid { display: none !important; }
        }
      `}</style>

      <BackgroundDecor animationTheme={effectiveBranding.animationTheme} />

      <Sidebar view={view} setView={setView} lowCount={totals.lowStock.length} role={myRole} pendingCount={pendingUsers.length} logo={effectiveLogo} onSignOut={handleSignOut} shops={shops} activeShopId={activeShopId} onSwitchShop={switchShop} />

      <main style={styles.main} className="depot-scroll depot-main">
        <TopBar
          view={view}
          role={myRole}
          onAdd={() => {
            if (view === 'inventory') setItemModal('new');
            if (view === 'suppliers') setSupplierModal('new');
            if (view === 'orders') setOrderModal('new');
            if (view === 'restock') setRestockModal(true);
          }}
        />

        {!canAccessView(myRole, view) ? (
          <AccessDenied />
        ) : (
        <>
        {view === 'overview' && (
          myRole === 'superadmin' ? (
            <ClientAccountsView
              clients={approvedUsers.filter((u) => u.role === 'client')}
              allUsers={approvedUsers}
              onManageSubscription={(client) => setSubscriptionModal(client)}
            />
          ) : (
            <Overview totals={totals} categoryData={categoryData} profitStats={profitStats} staffInventoryStats={staffInventoryStats} role={myRole} subscription={mySubscription} onQuickMove={(it) => setMoveModal(it)} />
          )
        )}

        {view === 'inventory' && (
          <InventoryView
            filtered={filtered}
            supplierMap={supplierMap}
            categories={categories}
            role={myRole}
            search={search} setSearch={setSearch}
            categoryFilter={categoryFilter} setCategoryFilter={setCategoryFilter}
            sortKey={sortKey} setSortKey={setSortKey}
            onEdit={(it) => setItemModal(it)}
            onDelete={(it) => setConfirmModal({ kind: 'item', target: it })}
            onMove={(it) => setMoveModal(it)}
            onEditMarkup={(it) => setMarkupModal(it)}
            onReturn={(it) => setReturnModal(it)}
          />
        )}

        {view === 'barcodes' && (
          <BarcodesView items={myOwnItems} categories={categories} canBackfill={can(myRole, 'editInventory')} />
        )}

        {view === 'staffInventory' && (
          <StaffInventoryView
            items={items}
            staffList={approvedUsers.filter((u) => u.role === 'staff')}
            selectedStaffUid={selectedStaffUid}
            setSelectedStaffUid={setSelectedStaffUid}
            onAssign={() => setAssignModal(true)}
            onEdit={(it) => setItemModal(it)}
            onDelete={(it) => setConfirmModal({ kind: 'item', target: it })}
            onMove={(it) => setMoveModal(it)}
            onReturn={(it) => setReturnModal(it)}
          />
        )}

        {view === 'clientAccounts' && (
          <ClientAccountsView
            clients={approvedUsers.filter((u) => u.role === 'client')}
            allUsers={approvedUsers}
            onManageSubscription={(client) => setSubscriptionModal(client)}
          />
        )}

        {view === 'suppliers' && (
          <SuppliersView
            suppliers={suppliers}
            items={items}
            onEdit={(s) => setSupplierModal(s)}
            onDelete={(s) => setConfirmModal({ kind: 'supplier', target: s })}
          />
        )}

        {view === 'orders' && (
          <OrdersView
            orders={shopOrders}
            onReceive={receiveOrder}
            onCancel={(o) => setConfirmModal({ kind: 'order', target: o })}
          />
        )}

        {view === 'restock' && (
          <RestockView restocks={shopRestocks} />
        )}

        {view === 'shops' && (
          <ShopsView shops={shops} activeShopId={activeShopId} onSwitch={switchShop} onCreate={createShop} onRename={renameShop} onDelete={(s) => setConfirmModal({ kind: 'shop', target: s })} />
        )}

        {view === 'categories' && (
          <CategoriesView
            categories={categories}
            items={items}
            onAdd={addCategory}
            onDelete={(name) => setConfirmModal({ kind: 'category', target: { name } })}
          />
        )}

        {view === 'locations' && (
          <LocationsView
            locations={locations}
            items={items}
            onAdd={addLocation}
            onDelete={(name) => setConfirmModal({ kind: 'location', target: { name } })}
          />
        )}

        {view === 'delivery' && (
          <DeliveryTimesView
            rows={deliveryRows}
            onUpdateStatus={(row) => setDeliveryStatusModal(row)}
            onViewHistory={(itemId) => {
              setHistItem(itemId);
              setHistSearch('');
              setHistType('All');
              setView('history');
            }}
          />
        )}

        {view === 'pos' && (
          <POSView items={myOwnItems} onCompleteSale={completeSale} shops={shops} activeShopId={activeShopId} onSwitchShop={switchShop} />
        )}

        {view === 'sales' && (
          <SalesHistoryView sales={myRole === 'staff' ? sales : shopSales} role={myRole} onCancelSale={(sale) => setConfirmModal({ kind: 'sale', target: sale })} onDeleteSale={(sale) => setConfirmModal({ kind: 'sale-delete', target: sale })} onLogActivity={logActivity} />
        )}

        {view === 'mysales' && (
          <MySalesView sales={sales} />
        )}

        {view === 'history' && (
          <TransactionHistoryView
            movements={filteredMovements}
            items={items}
            histSearch={histSearch} setHistSearch={setHistSearch}
            histType={histType} setHistType={setHistType}
            histItem={histItem} setHistItem={setHistItem}
          />
        )}

        {view === 'approvals' && (
          <TeamAccessView
            pendingUsers={pendingUsers}
            approvedUsers={approvedUsers}
            currentUid={user.uid}
            myRole={myRole}
            canCreateStaff={can(myRole, 'createStaff')}
            onCreateStaff={createStaffAccount}
            onApprove={approveUser}
            onDeny={denyUser}
            onRevoke={revokeUser}
            onChangeRole={changeUserRole}
            onSaveProfile={updateUserProfile}
            branding={effectiveBranding}
            onSaveLogo={saveLogo}
            onResetLogo={resetLogo}
            onSetTheme={setThemeKey}
            onSetFont={setFontKey}
            onSetInk={setCustomInk}
            onSetPanelBg={setCustomPanelBg}
            onSetSidebarBg={setCustomSidebarBg}
            onResetColors={resetCustomColors}
            onSetAnimationTheme={setAnimationTheme}
          />
        )}

        {view === 'activity' && (
          <ActivityLogView logs={loginLogs} myRole={myRole} approvedUsers={approvedUsers} pendingUsers={pendingUsers} />
        )}

        {view === 'myprofile' && (
          <MyProfileView profile={myProfile} uid={user.uid} role={myRole} subscription={mySubscription} onSave={updateUserProfile} onChangePassword={changePassword} />
        )}
        </>
        )}
      </main>

      {itemModal && (
        <ItemModal
          draft={itemModal === 'new' ? null : itemModal}
          suppliers={suppliers}
          categories={categories}
          locations={locations}
          items={myOwnItems}
          onClose={() => setItemModal(null)}
          onSave={saveItem}
        />
      )}

      {moveModal && (
        <MoveModal item={moveModal} allowIssue={can(myRole, 'stockIssue')} onClose={() => setMoveModal(null)} onSubmit={recordMovement} />
      )}

      {deliveryStatusModal && (
        <DeliveryStatusModal
          row={deliveryStatusModal}
          onClose={() => setDeliveryStatusModal(null)}
          onSave={updateDeliveryStatus}
          onClearOverride={clearDeliveryStatus}
        />
      )}

      {supplierModal && (
        <SupplierModal
          draft={supplierModal === 'new' ? null : supplierModal}
          onClose={() => setSupplierModal(null)}
          onSave={saveSupplier}
        />
      )}

      {orderModal && (
        <OrderModal
          draft={orderModal === 'new' ? null : orderModal}
          items={myOwnItems}
          suppliers={suppliers}
          onClose={() => setOrderModal(null)}
          onSave={saveOrder}
        />
      )}

      {restockModal && (
        <RestockModal
          items={myOwnItems}
          suppliers={suppliers}
          onClose={() => setRestockModal(false)}
          onSave={createRestock}
        />
      )}

      {assignModal && (
        <AssignInventoryModal
          myOwnItems={myOwnItems}
          staffList={approvedUsers.filter((u) => u.role === 'staff')}
          onClose={() => setAssignModal(null)}
          onSave={assignInventoryToStaff}
        />
      )}

      {markupModal && (
        <MarkupModal
          item={markupModal}
          onClose={() => setMarkupModal(null)}
          onSave={updateMarkup}
        />
      )}

      {returnModal && (
        <ReturnInventoryModal
          item={returnModal}
          hasDestination={!!(can(myRole, 'editInventory') && returnModal.sourceItemId && items.some((i) => i.id === returnModal.sourceItemId))}
          onClose={() => setReturnModal(null)}
          onSave={returnInventoryToAdmin}
        />
      )}

      {subscriptionModal && (
        <SubscriptionModal
          client={subscriptionModal}
          onClose={() => setSubscriptionModal(null)}
          onSave={saveSubscriptionPeriod}
          onDelete={(period) => setConfirmModal({ kind: 'subscription-delete', target: { client: subscriptionModal, period } })}
        />
      )}

      {confirmModal && confirmModal.kind === 'subscription-delete' && (
        <ConfirmModal
          title="DELETE SUBSCRIPTION RECORD"
          message={<>Permanently delete the <strong>{MONTH_NAMES[confirmModal.target.period.month - 1]} {confirmModal.target.period.year}</strong> subscription record for <strong>{confirmModal.target.client.fullName || confirmModal.target.client.email}</strong>? This can't be undone.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={async () => {
            await deleteSubscriptionPeriod(confirmModal.target.client.id, confirmModal.target.period);
            setConfirmModal(null);
          }}
          confirmLabel="Delete Record"
        />
      )}

      {confirmModal && confirmModal.kind === 'item' && (
        <ConfirmModal
          title="REMOVE ITEM"
          message={<>Remove <strong>{confirmModal.target.sku} — {confirmModal.target.name}</strong> from the manifest? This also clears its movement history.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteItem(confirmModal.target.id)}
        />
      )}

      {confirmModal && confirmModal.kind === 'supplier' && (
        <ConfirmModal
          title="REMOVE SUPPLIER"
          message={<>Remove <strong>{confirmModal.target.name}</strong>? Items linked to this supplier will be unlinked, not deleted.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteSupplier(confirmModal.target.id)}
        />
      )}

      {confirmModal && confirmModal.kind === 'order' && (
        <ConfirmModal
          title="CANCEL ORDER"
          message={<>Cancel the order for <strong>{confirmModal.target.quantity} × {confirmModal.target.itemSku}</strong> from <strong>{confirmModal.target.supplierName}</strong>? This won't affect stock.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => cancelOrder(confirmModal.target)}
          confirmLabel="Cancel Order"
        />
      )}

      {confirmModal && confirmModal.kind === 'shop' && (
        <ConfirmModal
          title="DELETE SHOP"
          message={<>Delete <strong>{confirmModal.target.name}</strong>? Its existing items, sales, and records are kept as-is (never deleted) — they'll just no longer be tagged to an active shop unless you reassign them.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => { deleteShop(confirmModal.target.id); setConfirmModal(null); }}
          confirmLabel="Delete Shop"
        />
      )}

      {confirmModal && confirmModal.kind === 'category' && (
        <ConfirmModal
          title="REMOVE CATEGORY"
          message={<>Remove the category <strong>{confirmModal.target.name}</strong>? This only works if no items currently use it.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteCategory(confirmModal.target.name)}
        />
      )}

      {confirmModal && confirmModal.kind === 'location' && (
        <ConfirmModal
          title="REMOVE LOCATION"
          message={<>Remove the location <strong>{confirmModal.target.name}</strong>? This only works if no items currently use it.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteLocation(confirmModal.target.name)}
        />
      )}

      {confirmModal && confirmModal.kind === 'sale' && (
        <ConfirmModal
          title="CANCEL SALE"
          message={<>Cancel sale <strong>{confirmModal.target.receiptNo}</strong> for {currency(confirmModal.target.total)}? This restores the sold quantities back into stock and can't be undone.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => cancelSale(confirmModal.target)}
          confirmLabel="Cancel Sale"
        />
      )}

      {confirmModal && confirmModal.kind === 'sale-delete' && (
        <ConfirmModal
          title="DELETE SALE RECORD"
          message={<>Permanently delete the cancelled sale <strong>{confirmModal.target.receiptNo}</strong>? This only removes the record from your table &mdash; it does not affect stock, since cancelling already restored it. This can't be undone.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteSale(confirmModal.target)}
          confirmLabel="Delete Sale"
        />
      )}

      {toast && (
        <div style={styles.toast}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--amber)' }} />
          {toast}
        </div>
      )}
    </div>
  );
}

