function Sidebar({ view, setView, lowCount, role, pendingCount, logo, onSignOut, shops, activeShopId, onSwitchShop }) {
  const structure = [
    { type: 'item', key: 'overview', label: 'Overview', icon: LayoutGrid },
    { type: 'item', key: 'pos', label: 'Point of Sale', icon: ShoppingCart },
    { type: 'group', label: 'Stock Management', icon: Boxes, children: [
      { key: 'inventory', label: 'Inventory', icon: Boxes },
      { key: 'barcodes', label: 'Barcodes', icon: Barcode },
      { key: 'staffInventory', label: 'Staff Inventory', icon: User },
      { key: 'suppliers', label: 'Suppliers', icon: Truck },
      { key: 'orders', label: 'Orders', icon: ClipboardList },
      { key: 'restock', label: 'Restock', icon: PackagePlus },
      { key: 'shops', label: 'Shops', icon: Store },
      { key: 'categories', label: 'Categories', icon: Tag },
      { key: 'locations', label: 'Zonal Locations', icon: MapPin },
    ] },
    { type: 'item', key: 'mysales', label: 'My Sales', icon: Receipt },
    { type: 'group', label: 'Reports', icon: ScrollText, children: [
      { key: 'delivery', label: 'Restock Records', icon: Timer },
      { key: 'sales', label: 'Sales History', icon: Receipt },
      { key: 'history', label: 'Transaction History', icon: ScrollText },
      { key: 'activity', label: 'Activity Log', icon: Clock },
    ] },
    { type: 'group', label: 'User Profiles', icon: User, children: [
      { key: 'approvals', label: 'Team', icon: User, badge: pendingCount },
      { key: 'myprofile', label: 'My Profile', icon: User },
    ] },
  ];

  // Resolve visibility: flat items check their own permission; groups are
  // shown only if at least one child is visible to this role, and only
  // their visible children render.
  const resolved = structure
    .map((entry) => {
      if (entry.type === 'item') {
        return canAccessView(role, entry.key) ? entry : null;
      }
      const children = entry.children.filter((c) => canAccessView(role, c.key));
      if (children.length === 0) return null;
      if (children.length === 1) {
        // Only one visible child - show it as a flat item instead of a
        // dropdown group wrapping a single link.
        return { type: 'item', key: children[0].key, label: children[0].label, icon: children[0].icon, badge: children[0].badge };
      }
      return { ...entry, children };
    })
    .filter(Boolean);

  const activeGroupLabel = resolved.find((e) => e.type === 'group' && e.children.some((c) => c.key === view))?.label;
  const [openGroup, setOpenGroup] = useState(activeGroupLabel || null);

  const toggleGroup = (label) => setOpenGroup((prev) => (prev === label ? null : label));

  return (
    <aside style={styles.sidebar} className="depot-sidebar">
      <div style={styles.brand} className="depot-brand">
        <div style={styles.logoCard}>
          <img src={logo} alt="Company logo" style={styles.logoImg} />
        </div>
      </div>
      {shops && shops.length > 0 && (
        <div style={{ padding: '0 4px', marginTop: 14 }}>
          <div style={{ fontSize: 9.5, fontWeight: 700, color: 'rgba(245,243,236,0.4)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 4 }}>
            Active Shop
          </div>
          <div style={{ position: 'relative' }}>
            <select
              value={activeShopId || ''}
              onChange={(e) => onSwitchShop(e.target.value)}
              style={{
                width: '100%', appearance: 'none', background: 'rgba(255,255,255,0.07)', color: '#fff',
                border: '1px solid rgba(255,255,255,0.15)', borderRadius: 7, padding: '7px 24px 7px 10px',
                fontSize: 12, fontWeight: 700, cursor: 'pointer',
              }}
            >
              {shops.map((s) => <option key={s.id} value={s.id} style={{ color: '#111' }}>{s.name}</option>)}
            </select>
            <ChevronDown size={13} color="rgba(255,255,255,0.5)" style={{ position: 'absolute', right: 7, top: 8, pointerEvents: 'none' }} />
          </div>
        </div>
      )}
      <nav style={{ display: 'flex', flexDirection: 'column', gap: 4, marginTop: 28 }} className="depot-sidebar-nav">
        {resolved.map((entry) => {
          if (entry.type === 'item') {
            const { key, label, icon: Icon } = entry;
            return (
              <button
                key={key}
                className={`depot-btn depot-nav-btn${view === key ? ' depot-nav-active' : ''}`}
                onClick={() => setView(key)}
                style={{
                  ...styles.navBtn,
                  background: view === key ? 'rgba(201,169,106,0.14)' : 'transparent',
                  color: view === key ? '#fff' : 'rgba(245,243,236,0.65)',
                  borderLeft: view === key ? '3px solid var(--amber)' : '3px solid transparent',
                }}
              >
                <Icon size={16} strokeWidth={2} />
                <span style={{ flex: 1, textAlign: 'left' }} className="depot-nav-label">{label}</span>
                {key === 'inventory' && lowCount > 0 && (
                  <span style={styles.navBadge}>{lowCount}</span>
                )}
              </button>
            );
          }
          const isOpen = openGroup === entry.label;
          const GroupIcon = entry.icon;
          const groupBadge = entry.children.reduce((sum, c) => sum + (c.badge || 0), 0);
          return (
            <div key={entry.label}>
              <button
                className="depot-btn depot-nav-btn"
                onClick={() => toggleGroup(entry.label)}
                style={{
                  ...styles.navBtn,
                  background: 'transparent', color: 'rgba(245,243,236,0.65)', borderLeft: '3px solid transparent',
                }}
              >
                <GroupIcon size={16} strokeWidth={2} />
                <span style={{ flex: 1, textAlign: 'left' }} className="depot-nav-label">{entry.label}</span>
                {groupBadge > 0 && <span style={styles.navBadge}>{groupBadge}</span>}
                <ChevronDown size={13} style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s ease' }} />
              </button>
              {isOpen && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 2, marginTop: 2 }}>
                  {entry.children.map(({ key, label, icon: Icon, badge }) => (
                    <button
                      key={key}
                      className={`depot-btn depot-nav-btn${view === key ? ' depot-nav-active' : ''}`}
                      onClick={() => setView(key)}
                      style={{
                        ...styles.navBtn, paddingLeft: 34, fontSize: 12.5,
                        background: view === key ? 'rgba(201,169,106,0.14)' : 'transparent',
                        color: view === key ? '#fff' : 'rgba(245,243,236,0.55)',
                        borderLeft: view === key ? '3px solid var(--amber)' : '3px solid transparent',
                      }}
                    >
                      <Icon size={14} strokeWidth={2} />
                      <span style={{ flex: 1, textAlign: 'left' }} className="depot-nav-label">{label}</span>
                      {badge > 0 && <span style={styles.navBadge}>{badge}</span>}
                    </button>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </nav>
      <div style={styles.sidebarFoot} className="depot-sidebar-foot">
        <Clock size={12} />
        <span>{new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}</span>
      </div>
      <button
        className="depot-btn depot-signout-btn"
        onClick={onSignOut}
        style={{
          marginTop: 8, background: 'transparent', border: '1px solid rgba(245,243,236,0.2)',
          color: 'rgba(245,243,236,0.7)', fontSize: 11.5, borderRadius: 5, padding: '7px 12px',
        }}
      >
        Sign Out
      </button>
    </aside>
  );
}

function TopBar({ view, role, onAdd }) {
  const titles = {
    overview: role === 'superadmin'
      ? ['Client Accounts', 'Manage subscriptions for every business on the platform']
      : ['Overview', 'Warehouse status at a glance'],
    pos: ['Point of Sale', 'Ring up a sale and update stock'],
    inventory: ['Inventory', 'Every SKU on the floor'],
    barcodes: ['Barcodes', 'Generate, print, and download barcode labels'],
    staffInventory: ['Staff Inventory', 'Stock assigned to each staff member'],
    clientAccounts: ['Client Accounts', 'Manage subscriptions for every business on the platform'],
    suppliers: ['Suppliers', 'Vendors you order stock from'],
    orders: ['Orders', 'Purchase orders placed with your suppliers'],
    restock: ['Restock', 'Receive inventory, with or without a supplier'],
    shops: ['Shops', 'Create and switch between shops within your business'],
    categories: ['Categories', 'Organize items into your own groups'],
    locations: ['Zonal Locations', 'Manage where stock is stored'],
    delivery: ['Restock Records', 'Lead times and expected restocks'],
    sales: ['Sales History', 'Every completed transaction'],
    history: ['Transaction History', 'Full receiving & issue ledger'],
    approvals: ['Team', 'Manage your team roster, roles, and approvals'],
    mysales: ['My Sales', 'Transactions you\'ve processed'],
    activity: ['Activity Log', 'Sign-in and sign-out history'],
    myprofile: ['My Profile', 'Your personal details'],
  };
  const [title, sub] = titles[view];
  const showAdd = (view === 'inventory' && can(role, 'editInventory')) || (view === 'suppliers' && can(role, 'manageSuppliers'))
    || (view === 'orders' && can(role, 'manageOrders')) || (view === 'restock' && can(role, 'stockReceive'));
  const showManualLink = view === 'overview';
  return (
    <div style={styles.topbar} className="depot-topbar">
      <div>
        <h1 style={styles.h1} className="depot-h1">{title}</h1>
        <p style={styles.subtext}>{sub}</p>
      </div>
      {showAdd && (
        <button className="depot-btn depot-no-print depot-topbar-btn" style={styles.primaryBtn} onClick={onAdd}>
          <Plus size={16} /> {view === 'suppliers' ? 'New Supplier' : view === 'orders' ? 'New Order' : view === 'restock' ? 'New Restock' : 'New Item'}
        </button>
      )}
      {showManualLink && (
        <a
          href="/Stock-IT-User-Manual.pdf"
          download
          className="depot-btn depot-no-print depot-topbar-btn"
          style={{ ...styles.primaryBtn, textDecoration: 'none' }}
        >
          <Download size={16} /> Download User Manual
        </a>
      )}
    </div>
  );
}

function StatCard({ icon: Icon, label, value, accent }) {
  return (
    <div style={styles.statCard} className="depot-stat-card">
      <div style={{ ...styles.statIcon, background: accent }}>
        <Icon size={18} color="#fff" strokeWidth={2.2} />
      </div>
      <div>
        <div style={styles.statValue}>{value}</div>
        <div style={styles.statLabel}>{label}</div>
      </div>
    </div>
  );
}

// Shown to a Client Admin only (their own subscription). This is
// deliberately NOT dismissible - it's computed live from the real
// subscription data every render, so the only way it goes away is if
// Super Admin actually sets a later expiration date. There's no stored
// "dismissed" flag to work around.
function SubscriptionStatusBanner({ subscription }) {
  const latest = getLatestSubscriptionPeriod(subscription);
  if (!latest) return null; // Super Admin hasn't set up a subscription yet - nothing to show
  const days = daysUntilExpiration(subscription);
  const expiringSoon = days !== null && days >= 0 && days <= 5;

  if (expiringSoon) {
    return (
      <div style={{
        display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', borderRadius: 8,
        background: 'rgba(193,80,58,0.1)', border: '1px solid rgba(193,80,58,0.35)', marginBottom: 16,
      }}>
        <AlertTriangle size={18} color="var(--red)" style={{ flexShrink: 0 }} />
        <div style={{ fontSize: 13, color: 'var(--ink)' }}>
          <strong>Your subscription expires in {days} day{days === 1 ? '' : 's'}</strong>, on {formatDate(latest.endDate)}.
          Please contact your platform administrator to renew &mdash; this notice will stay until it's renewed.
        </div>
      </div>
    );
  }
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 10, padding: '10px 16px', borderRadius: 8,
      background: 'rgba(79,138,99,0.08)', border: '1px solid rgba(79,138,99,0.25)', marginBottom: 16,
    }}>
      <CheckCircle2 size={16} color="var(--green)" style={{ flexShrink: 0 }} />
      <div style={{ fontSize: 12.5, color: 'var(--ink)' }}>
        Subscription active until <strong>{formatDate(latest.endDate)}</strong>.
      </div>
    </div>
  );
}

function Overview({ totals, categoryData, profitStats, staffInventoryStats, role, subscription, onQuickMove }) {
  const canViewProfit = can(role, 'viewSalesReports');
  const canViewMySales = can(role, 'viewOwnSales');
  const canViewStaffInventory = can(role, 'editInventory');
  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      {role === 'client' && <SubscriptionStatusBanner subscription={subscription} />}
      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Package} label="SKUs Tracked" value={totals.totalSkus} accent="var(--blueprint)" />
        <StatCard icon={Boxes} label="Units on Hand" value={totals.totalUnits.toLocaleString()} accent="#2E5C87" />
        <StatCard icon={PesoIcon} label="Inventory Value" value={currency(totals.totalValue)} accent="var(--green)" />
        <StatCard icon={AlertTriangle} label="Low Stock Alerts" value={totals.lowStock.length} accent={totals.lowStock.length ? 'var(--red)' : 'var(--blueprint)'} />
      </div>

      <div style={styles.overviewGrid} className="depot-overview-grid">
        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <ListOrdered size={15} />
            <span>UNITS BY CATEGORY</span>
          </div>
          <div style={{ height: 220 }}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={categoryData} margin={{ top: 10, right: 10, left: -10, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(59,42,31,0.08)" vertical={false} />
                <XAxis dataKey="category" tick={{ fontFamily: 'Quicksand', fontSize: 11, fill: '#3B2A1F' }} axisLine={{ stroke: 'rgba(59,42,31,0.15)' }} tickLine={false} />
                <YAxis tick={{ fontFamily: 'Quicksand', fontSize: 11, fill: '#3B2A1F' }} axisLine={false} tickLine={false} />
                <Tooltip
                  contentStyle={{ fontFamily: 'Quicksand', fontSize: 12, border: '1px solid #3B2A1F', borderRadius: 4 }}
                  cursor={{ fill: 'rgba(15,42,71,0.06)' }}
                />
                <Bar dataKey="units" radius={[3, 3, 0, 0]}>
                  {categoryData.map((_, idx) => (
                    <Cell key={idx} fill={idx % 2 === 0 ? '#2F4A32' : '#C9A96A'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <AlertTriangle size={15} />
            <span>REORDER WATCHLIST</span>
          </div>
          {totals.lowStock.length === 0 ? (
            <div style={styles.emptyState}>All items are above their reorder point.</div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
              {totals.lowStock.map((it) => (
                <div key={it.id} style={styles.watchRow}>
                  <div>
                    <div style={styles.watchSku}>{it.sku}</div>
                    <div style={styles.watchName}>{it.name}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <span style={styles.watchQty}>{it.quantity} / {it.reorderPoint}</span>
                    <button className="depot-btn" style={styles.smallAmberBtn} onClick={() => onQuickMove(it)}>
                      Receive
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Profit is commercially sensitive (it reveals cost basis and
          margins) - only managers who can already view Reports get to see
          it. Staff never see this section, even though they see Overview. */}
      {canViewProfit && (
        <>
          <div style={{ ...styles.panelHeader, marginTop: 24, marginBottom: 10 }}>
            <PesoIcon size={15} />
            <span>PROFIT TRACKER</span>
          </div>

          <div style={styles.statGrid} className="depot-stat-grid">
            <StatCard icon={PesoIcon} label="Total Profit" value={currency(profitStats.totalProfit)} accent={profitStats.totalProfit >= 0 ? 'var(--green)' : 'var(--red)'} />
            <StatCard icon={Receipt} label="Total Revenue" value={currency(profitStats.totalRevenue)} accent="var(--blueprint)" />
            <StatCard icon={Package} label="Cost of Goods Sold" value={currency(profitStats.totalCost)} accent="#2E5C87" />
            <StatCard icon={CheckCircle2} label="Profit Margin" value={`${profitStats.margin.toFixed(1)}%`} accent={profitStats.margin >= 0 ? 'var(--green)' : 'var(--red)'} />
          </div>

          <div style={styles.overviewGrid} className="depot-overview-grid">
            <div style={styles.panel}>
              <div style={styles.panelHeader}>
                <Boxes size={15} />
                <span>PROFIT BY ITEM</span>
              </div>
              {profitStats.profitByItem.length === 0 ? (
                <div style={styles.emptyState}>No completed sales yet.</div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10, maxHeight: 240, overflowY: 'auto' }} className="depot-scroll">
                  {profitStats.profitByItem.slice(0, 10).map((row) => (
                    <div key={row.itemId} style={styles.watchRow}>
                      <div>
                        <div style={styles.watchSku}>{row.sku}</div>
                        <div style={styles.watchName}>{row.name} · {row.qty} sold</div>
                      </div>
                      <span style={{ fontWeight: 700, color: row.profit >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(row.profit)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div style={styles.panel}>
              <div style={styles.panelHeader}>
                <Receipt size={15} />
                <span>PROFIT PER SALE</span>
              </div>
              {profitStats.perSale.length === 0 ? (
                <div style={styles.emptyState}>No completed sales yet.</div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10, maxHeight: 240, overflowY: 'auto' }} className="depot-scroll">
                  {profitStats.perSale.map((s) => (
                    <div key={s.id} style={styles.watchRow}>
                      <div>
                        <div style={styles.watchSku}>{s.receiptNo}</div>
                        <div style={styles.watchName}>{formatDate(s.timestamp)} · Revenue {currency(s.revenue)}</div>
                      </div>
                      <span style={{ fontWeight: 700, color: s.profit >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(s.profit)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </>
      )}

      {/* Value of stock currently out with staff, broken down per staff
          member - managers only, same tier as the Staff Inventory
          management page itself. */}
      {canViewStaffInventory && (
        <>
          <div style={{ ...styles.panelHeader, marginTop: 24, marginBottom: 10 }}>
            <User size={15} />
            <span>STAFF INVENTORY VALUE</span>
          </div>
          <div style={styles.statGrid} className="depot-stat-grid">
            <StatCard icon={PesoIcon} label="Total Value With Staff" value={currency(staffInventoryStats.total)} accent="var(--green)" />
            <StatCard icon={User} label="Staff Holding Stock" value={staffInventoryStats.byStaff.length} accent="var(--blueprint)" />
          </div>
          <div style={styles.panel}>
            {staffInventoryStats.byStaff.length === 0 ? (
              <div style={styles.emptyState}>No inventory has been assigned to staff yet.</div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 4 }}>
                {staffInventoryStats.byStaff.map((s) => (
                  <div key={s.staffUid} style={styles.watchRow}>
                    <div>
                      <div style={styles.watchSku}>{s.name}</div>
                      <div style={styles.watchName}>{s.skuCount} SKU{s.skuCount === 1 ? '' : 's'} · {s.units} unit{s.units === 1 ? '' : 's'}</div>
                    </div>
                    <span style={{ fontWeight: 700, fontFamily: "'Quicksand', sans-serif", color: 'var(--ink)' }}>{currency(s.value)}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}

      {/* A staff member's own sales performance - their own scoped data
          only, since `profitStats` is already computed from whatever
          `sales` this role can see (their own sales, for staff). */}
      {canViewMySales && (
        <>
          <div style={{ ...styles.panelHeader, marginTop: 24, marginBottom: 10 }}>
            <Receipt size={15} />
            <span>MY SALES</span>
          </div>
          <div style={styles.statGrid} className="depot-stat-grid">
            <StatCard icon={Receipt} label="My Total Revenue" value={currency(profitStats.totalRevenue)} accent="var(--blueprint)" />
            <StatCard icon={PesoIcon} label="My Total Profit" value={currency(profitStats.totalProfit)} accent={profitStats.totalProfit >= 0 ? 'var(--green)' : 'var(--red)'} />
            <StatCard icon={CheckCircle2} label="My Margin" value={`${profitStats.margin.toFixed(1)}%`} accent={profitStats.margin >= 0 ? 'var(--green)' : 'var(--red)'} />
          </div>
          <div style={styles.panel}>
            <div style={styles.panelHeader}>
              <ScrollText size={15} />
              <span>MY RECENT SALES</span>
            </div>
            {profitStats.perSale.length === 0 ? (
              <div style={styles.emptyState}>No sales recorded yet — ring one up in Point of Sale.</div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
                {profitStats.perSale.map((s) => (
                  <div key={s.id} style={styles.watchRow}>
                    <div>
                      <div style={styles.watchSku}>{s.receiptNo}</div>
                      <div style={styles.watchName}>{formatDate(s.timestamp)} · Revenue {currency(s.revenue)}</div>
                    </div>
                    <span style={{ fontWeight: 700, color: s.profit >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(s.profit)}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

// Renders one scannable barcode + item name + SKU + optional price, as a
// small canvas-based label. Used both in the on-screen browse grid and
// (via the same component) in the hidden print-only sheet.
function BarcodeLabel({ item, showPrice = true }) {
  const canvasRef = useRef(null);
  useEffect(() => {
    if (!canvasRef.current || !item?.barcode) return;
    try {
      JsBarcode(canvasRef.current, item.barcode, {
        format: 'CODE128', width: 1.6, height: 42, displayValue: false, margin: 0,
        background: '#ffffff', lineColor: '#111111',
      });
    } catch (e) {
      // Non-barcode-safe characters somehow ended up in item.barcode -
      // leave the canvas blank rather than crashing the whole page.
    }
  }, [item?.barcode]);
  return (
    <div className="barcode-label" style={{
      display: 'inline-flex', flexDirection: 'column', alignItems: 'center', gap: 3,
      padding: '10px 12px', border: '1px solid #ddd', borderRadius: 4, background: '#fff', width: 180,
      breakInside: 'avoid',
    }}>
      <div style={{
        fontSize: 11, fontWeight: 700, textAlign: 'center', color: '#111', width: '100%',
        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
      }}>
        {item.name}
      </div>
      <canvas ref={canvasRef} style={{ maxWidth: '100%' }} />
      <div style={{ fontSize: 10, color: '#333', letterSpacing: '0.03em', fontFamily: "'IBM Plex Mono', monospace" }}>{item.sku}</div>
      {showPrice && (
        <div style={{ fontSize: 12, fontWeight: 700, color: '#111' }}>{currency(item.sellingPrice ?? item.unitCost ?? 0)}</div>
      )}
    </div>
  );
}

function BarcodesView({ items, categories, canBackfill }) {
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [selected, setSelected] = useState(() => new Set());
  const [includePrice, setIncludePrice] = useState(true);
  const [printBatch, setPrintBatch] = useState(null);

  // Items created before this feature existed won't have a `barcode` yet.
  // saveItem() only assigns one the next time each item is individually
  // edited, which would otherwise leave this whole page looking empty for
  // any pre-existing inventory - so back-fill any missing ones right away
  // instead of waiting on that. Self-terminating: once an item's barcode
  // is written, it no longer shows up in `missing` on the next pass.
  useEffect(() => {
    if (!canBackfill) return;
    const missing = items.filter((it) => !it.barcode);
    if (missing.length === 0) return;
    missing.forEach((it) => {
      setDoc(doc(db, 'items', it.id), { barcode: generateBarcodeValue() }, { merge: true }).catch(() => {});
    });
  }, [items, canBackfill]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    return items.filter((it) => {
      const matchesSearch = !q || it.name.toLowerCase().includes(q) || (it.sku || '').toLowerCase().includes(q);
      const matchesCat = categoryFilter === 'All' || it.category === categoryFilter;
      return matchesSearch && matchesCat;
    });
  }, [items, search, categoryFilter]);

  const allSelected = filtered.length > 0 && filtered.every((it) => selected.has(it.id));

  const toggleOne = (id) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    setSelected((prev) => {
      if (allSelected) {
        const next = new Set(prev);
        filtered.forEach((it) => next.delete(it.id));
        return next;
      }
      const next = new Set(prev);
      filtered.forEach((it) => next.add(it.id));
      return next;
    });
  };

  const selectedItems = useMemo(() => items.filter((it) => selected.has(it.id)), [items, selected]);

  useEffect(() => {
    const clear = () => setPrintBatch(null);
    window.addEventListener('afterprint', clear);
    return () => window.removeEventListener('afterprint', clear);
  }, []);

  const triggerPrint = (list) => {
    if (list.length === 0) return;
    setPrintBatch(list);
    setTimeout(() => window.print(), 60);
  };

  const downloadPDF = (list) => {
    if (list.length === 0) return;
    const doc = new jsPDF({ unit: 'mm', format: 'a4' });
    const pageW = 210, pageH = 297;
    const marginX = 10, marginY = 12;
    const labelW = 60, labelH = 32, gapX = 4, gapY = 4;
    const cols = Math.max(1, Math.floor((pageW - marginX * 2 + gapX) / (labelW + gapX)));
    let col = 0, x = marginX, y = marginY;

    list.forEach((it) => {
      const canvas = document.createElement('canvas');
      let imgData = null;
      try {
        JsBarcode(canvas, it.barcode, { format: 'CODE128', width: 2, height: 40, displayValue: false, margin: 0 });
        imgData = canvas.toDataURL('image/png');
      } catch (e) { /* skip an unrenderable barcode rather than aborting the whole PDF */ }

      if (y + labelH > pageH - marginY) {
        doc.addPage();
        col = 0; x = marginX; y = marginY;
      }

      doc.setDrawColor(210);
      doc.rect(x, y, labelW, labelH);
      doc.setFont(undefined, 'bold');
      doc.setFontSize(8);
      const name = (it.name || '').length > 28 ? it.name.slice(0, 27) + '…' : (it.name || '');
      doc.text(name, x + labelW / 2, y + 5.5, { align: 'center' });

      if (imgData) doc.addImage(imgData, 'PNG', x + 5, y + 8, labelW - 10, 12);

      doc.setFont(undefined, 'normal');
      doc.setFontSize(7.5);
      doc.text(it.sku || '', x + labelW / 2, y + 23.5, { align: 'center' });

      if (includePrice) {
        doc.setFont(undefined, 'bold');
        doc.setFontSize(9.5);
        doc.text(currency(it.sellingPrice ?? it.unitCost ?? 0), x + labelW / 2, y + 29, { align: 'center' });
      }

      col++;
      if (col >= cols) { col = 0; x = marginX; y += labelH + gapY; }
      else { x += labelW + gapX; }
    });

    doc.save(`stock-it-barcodes-${Date.now()}.pdf`);
  };

  return (
    <div>
      <div className="depot-no-print depot-filterbar" style={{ ...styles.filterBar, flexWrap: 'wrap', gap: 10 }}>
        <div style={{ position: 'relative', flex: '1 1 220px' }}>
          <Search size={14} style={{ position: 'absolute', left: 10, top: 10, color: 'rgba(59,42,31,0.4)' }} />
          <input
            className="depot-input" placeholder="Search by item name or SKU..."
            style={{ ...styles.modalInput, paddingLeft: 30, width: '100%' }}
            value={search} onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <select className="depot-select" style={{ ...styles.modalInput, width: 170 }}
          value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)}>
          <option value="All">All Categories</option>
          {categories.map((c) => <option key={c} value={c}>{c}</option>)}
        </select>
        <label style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 12.5, color: 'var(--ink)', cursor: 'pointer' }}>
          <input type="checkbox" checked={includePrice} onChange={(e) => setIncludePrice(e.target.checked)} />
          Show Selling Price
        </label>
      </div>

      <div className="depot-no-print depot-filterbar depot-barcode-toolbar" style={{ ...styles.filterBar, gap: 10, flexWrap: 'wrap' }}>
        <button className="depot-btn" style={{ ...styles.ghostBtn, display: 'flex', alignItems: 'center', gap: 6 }} onClick={toggleAll}>
          {allSelected ? <CheckSquare size={15} /> : <Square size={15} />}
          {allSelected ? 'Unselect All' : 'Select All'} ({filtered.length})
        </button>
        <div style={{ fontSize: 12.5, color: 'rgba(59,42,31,0.6)' }}>{selected.size} selected</div>
        <div style={{ flex: 1 }} />
        <button className="depot-btn" style={{ ...styles.ghostBtn, display: 'flex', alignItems: 'center', gap: 6, opacity: selectedItems.length ? 1 : 0.4 }}
          disabled={!selectedItems.length} onClick={() => triggerPrint(selectedItems)}>
          <Printer size={14} /> Print Selected
        </button>
        <button className="depot-btn" style={{ ...styles.ghostBtn, display: 'flex', alignItems: 'center', gap: 6, opacity: selectedItems.length ? 1 : 0.4 }}
          disabled={!selectedItems.length} onClick={() => downloadPDF(selectedItems)}>
          <Download size={14} /> Download Selected
        </button>
        <button className="depot-btn" style={{ ...styles.primaryBtn, display: 'flex', alignItems: 'center', gap: 6, opacity: filtered.length ? 1 : 0.4 }}
          disabled={!filtered.length} onClick={() => triggerPrint(filtered)}>
          <Printer size={14} /> Print All
        </button>
        <button className="depot-btn" style={{ ...styles.primaryBtn, display: 'flex', alignItems: 'center', gap: 6, opacity: filtered.length ? 1 : 0.4 }}
          disabled={!filtered.length} onClick={() => downloadPDF(filtered)}>
          <Download size={14} /> Download All
        </button>
      </div>

      {filtered.length === 0 ? (
        <div className="depot-no-print" style={{ textAlign: 'center', padding: '60px 0', color: 'rgba(59,42,31,0.45)', fontSize: 13.5 }}>
          {items.length === 0
            ? 'No inventory items yet — add some from the Inventory tab first.'
            : 'No items match your search/filter.'}
        </div>
      ) : (
        <div className="barcode-browse-grid" style={{ display: 'flex', flexWrap: 'wrap', gap: 14, marginTop: 4 }}>
          {filtered.map((it) => (
            <div key={it.id} style={{ position: 'relative' }}>
              <label style={{
                position: 'absolute', top: 6, left: 6, zIndex: 2, background: 'rgba(255,255,255,0.9)',
                borderRadius: 4, padding: 2, display: 'flex', cursor: 'pointer',
              }}>
                <input type="checkbox" checked={selected.has(it.id)} onChange={() => toggleOne(it.id)} />
              </label>
              <BarcodeLabel item={it} showPrice={includePrice} />
            </div>
          ))}
        </div>
      )}

      {printBatch && (
        <div className="barcode-print-only" style={{ display: 'none' }}>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
            {printBatch.map((it) => <BarcodeLabel key={it.id} item={it} showPrice={includePrice} />)}
          </div>
        </div>
      )}
    </div>
  );
}

function InventoryView({ filtered, supplierMap, categories, role, search, setSearch, categoryFilter, setCategoryFilter, sortKey, setSortKey, onEdit, onDelete, onMove, onEditMarkup, onReturn }) {
  const supplierNames = (it) => getSupplierIds(it).map((sid) => supplierMap[sid]?.name).filter(Boolean);
  const itemMarkup = (it) => computeMarkupFromPrices(it.unitCost, it.sellingPrice ?? it.unitCost);
  const itemEstProfit = (it) => it.quantity * itemMarkup(it).amount;

  const totalQty = filtered.reduce((s, it) => s + it.quantity, 0);
  const totalBaseCostValue = filtered.reduce((s, it) => s + it.quantity * it.unitCost, 0);
  const totalSellingValue = filtered.reduce((s, it) => s + it.quantity * (it.sellingPrice ?? it.unitCost), 0);
  const totalEstProfit = totalSellingValue - totalBaseCostValue;

  const exportHeaders = ['SKU', 'Name', 'Category', 'Suppliers', 'Location', 'Quantity', 'Base Cost', 'Selling Price', 'Markup', 'Base Cost Total Value', 'Selling Price Total Value', 'Est. Profit'];
  const exportRows = () => [
    ...filtered.map((it) => {
      const markup = itemMarkup(it);
      return [
        it.sku, it.name, it.category, supplierNames(it).join('; '), it.location,
        it.quantity, (Number(it.unitCost) || 0).toFixed(2), (Number(it.sellingPrice ?? it.unitCost) || 0).toFixed(2),
        `${currency(markup.amount)} (${markup.percent.toFixed(1)}%)`,
        (it.quantity * (Number(it.unitCost) || 0)).toFixed(2), (it.quantity * (Number(it.sellingPrice ?? it.unitCost) || 0)).toFixed(2),
        itemEstProfit(it).toFixed(2),
      ];
    }),
    ['TOTAL', '', '', '', '', totalQty, '', '', '', totalBaseCostValue.toFixed(2), totalSellingValue.toFixed(2), totalEstProfit.toFixed(2)],
  ];
  const handleDownload = () => downloadCSV('inventory.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('inventory.pdf', 'Inventory', exportHeaders, exportRows());
  const canEdit = can(role, 'editInventory');
  const canEditMarkup = can(role, 'editMarkup');
  const canDelete = can(role, 'deleteInventory');
  const canMove = can(role, 'stockReceive') || can(role, 'stockIssue');
  const showActionsCol = canEdit || canDelete || canMove || canEditMarkup;

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      {can(role, 'print') && <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />}
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search by name or SKU…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <select className="depot-select" value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)} style={styles.select}>
          <option value="All">All Categories</option>
          {categories.map((c) => <option key={c} value={c}>{c}</option>)}
        </select>
        <select className="depot-select" value={sortKey} onChange={(e) => setSortKey(e.target.value)} style={styles.select}>
          <option value="name">Sort: Name</option>
          <option value="qty">Sort: Quantity</option>
          <option value="value">Sort: Value</option>
          <option value="low">Sort: Closest to Reorder</option>
        </select>
      </div>

      <div style={styles.tableWrap} className="depot-scroll">
        <table style={styles.table} className="depot-table">
          <thead>
            <tr>
              {['SKU', 'Item', 'Category', 'Suppliers', 'Location', 'Qty', 'Base Cost', 'Selling Price', 'Markup', 'Base Cost Total Value', 'Selling Price Total Value', 'Est. Profit', ...(showActionsCol ? [''] : [])].map((h) => (
                <th key={h} style={styles.th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={13} style={{ ...styles.td, textAlign: 'center', padding: '32px 0', color: 'rgba(59,42,31,0.5)' }}>No items match your search.</td></tr>
            )}
            {filtered.map((it) => {
              const low = it.quantity <= it.reorderPoint;
              const names = supplierNames(it);
              return (
                <tr key={it.id} className="depot-row">
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500 }}>{it.sku}</td>
                  <td style={styles.td}>{it.name}</td>
                  <td style={styles.td}><span style={styles.pill}>{it.category}</span></td>
                  <td style={{ ...styles.td, fontSize: 12.5, color: names.length ? 'var(--ink)' : 'rgba(59,42,31,0.4)' }}>
                    {names.length ? names.join(', ') : '— none —'}
                  </td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontSize: 12, color: it.location ? 'rgba(59,42,31,0.6)' : 'rgba(59,42,31,0.4)' }}>
                    <MapPin size={11} style={{ marginRight: 3, verticalAlign: -1 }} />{it.location || '— none —'}
                  </td>
                  <td style={styles.td}>
                    <span style={{ color: low ? 'var(--red)' : 'var(--ink)', fontWeight: low ? 700 : 500 }}>{it.quantity}</span>
                    {low && <AlertTriangle size={12} color="var(--red)" style={{ marginLeft: 5, verticalAlign: -1 }} />}
                    {it.units && it.units.length > 0 && (() => {
                      const counts = getUnitCounts(it);
                      const units = getItemUnits(it);
                      return (
                        <div style={{ fontSize: 10.5, color: 'rgba(59,42,31,0.5)', marginTop: 2 }}>
                          {units.map((u) => `${counts[u.name]} ${u.name}${counts[u.name] === 1 ? '' : 's'}`).join(' • ')}
                        </div>
                      );
                    })()}
                  </td>
                  <td style={styles.td}>{currency(it.unitCost)}</td>
                  <td style={styles.td}>{currency(it.sellingPrice ?? it.unitCost)}</td>
                  <td style={{ ...styles.td, fontSize: 12.5 }}>
                    {(() => { const m = itemMarkup(it); return `${currency(m.amount)} (${m.percent.toFixed(1)}%)`; })()}
                  </td>
                  <td style={styles.td}>{currency(it.quantity * it.unitCost)}</td>
                  <td style={{ ...styles.td, fontWeight: 600, color: 'var(--green)' }}>{currency(it.quantity * (it.sellingPrice ?? it.unitCost))}</td>
                  <td style={{ ...styles.td, fontWeight: 600, color: itemEstProfit(it) >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(itemEstProfit(it))}</td>
                  {showActionsCol && (
                    <td className="depot-no-print" style={{ ...styles.td, display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                      {canMove && <IconBtn onClick={() => onMove(it)} title="Record movement"><ArrowUpCircle size={15} /></IconBtn>}
                      {canEdit && <IconBtn onClick={() => onEdit(it)} title="Edit"><Pencil size={14} /></IconBtn>}
                      {!canEdit && canEditMarkup && <IconBtn onClick={() => onEditMarkup(it)} title="Update markup"><PesoIcon size={14} /></IconBtn>}
                      {!canEdit && canEditMarkup && <IconBtn onClick={() => onReturn(it)} title="Return to Client Admin"><Undo2 size={14} /></IconBtn>}
                      {canDelete && <IconBtn onClick={() => onDelete(it)} title="Delete" danger><Trash2 size={14} /></IconBtn>}
                    </td>
                  )}
                </tr>
              );
            })}
            {filtered.length > 0 && (
              <tr style={{ borderTop: '2px solid rgba(59,42,31,0.25)', fontWeight: 700 }}>
                <td style={styles.td} colSpan={5}>TOTAL</td>
                <td style={styles.td}>{totalQty}</td>
                <td style={styles.td}></td>
                <td style={styles.td}></td>
                <td style={styles.td}></td>
                <td style={styles.td}>{currency(totalBaseCostValue)}</td>
                <td style={{ ...styles.td, color: 'var(--green)' }}>{currency(totalSellingValue)}</td>
                <td style={{ ...styles.td, color: totalEstProfit >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(totalEstProfit)}</td>
                {showActionsCol && <td className="depot-no-print" style={styles.td}></td>}
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function StaffInventoryView({ items, staffList, selectedStaffUid, setSelectedStaffUid, onAssign, onEdit, onDelete, onMove, onReturn }) {
  const staffItems = useMemo(
    () => items.filter((it) => it.holderId === selectedStaffUid),
    [items, selectedStaffUid]
  );
  const selectedStaff = staffList.find((s) => s.id === selectedStaffUid);

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <select className="depot-select" value={selectedStaffUid} onChange={(e) => setSelectedStaffUid(e.target.value)} style={styles.select}>
          <option value="">— Select a staff member —</option>
          {staffList.map((s) => <option key={s.id} value={s.id}>{s.fullName || s.email}</option>)}
        </select>
        {selectedStaffUid && (
          <button className="depot-btn" style={styles.primaryBtn} onClick={onAssign}>
            <Plus size={16} /> Assign Inventory
          </button>
        )}
      </div>

      {staffList.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No staff accounts yet — create one from Team Access.</div></div>
      ) : !selectedStaffUid ? (
        <div style={styles.panel}><div style={styles.emptyState}>Pick a staff member above to view and manage their inventory.</div></div>
      ) : staffItems.length === 0 ? (
        <div style={styles.panel}>
          <div style={styles.emptyState}>{selectedStaff?.fullName || selectedStaff?.email} has no assigned inventory yet.</div>
        </div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['SKU', 'Item', 'Category', 'Qty', 'Base Cost', 'Markup', 'Selling Price', 'Value', ''].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {staffItems.map((it) => {
                const low = it.quantity <= it.reorderPoint;
                const markupLabel = it.markupType === 'fixed' ? `${currency(it.markupValue || 0)} flat` : `${it.markupValue || 0}%`;
                return (
                  <tr key={it.id} className="depot-row">
                    <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500 }}>{it.sku}</td>
                    <td style={styles.td}>{it.name}</td>
                    <td style={styles.td}><span style={styles.pill}>{it.category}</span></td>
                    <td style={styles.td}>
                      <span style={{ color: low ? 'var(--red)' : 'var(--ink)', fontWeight: low ? 700 : 500 }}>{it.quantity}</span>
                      {low && <AlertTriangle size={12} color="var(--red)" style={{ marginLeft: 5, verticalAlign: -1 }} />}
                    </td>
                    <td style={styles.td}>{currency(it.unitCost)}</td>
                    <td style={styles.td}>{markupLabel}</td>
                    <td style={styles.td}>{currency(it.sellingPrice ?? it.unitCost)}</td>
                    <td style={styles.td}>{currency(it.quantity * it.unitCost)}</td>
                    <td className="depot-no-print" style={{ ...styles.td, display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                      <IconBtn onClick={() => onMove(it)} title="Record movement"><ArrowUpCircle size={15} /></IconBtn>
                      <IconBtn onClick={() => onEdit(it)} title="Edit"><Pencil size={14} /></IconBtn>
                      <IconBtn onClick={() => onReturn(it)} title="Return to my inventory"><Undo2 size={14} /></IconBtn>
                      <IconBtn onClick={() => onDelete(it)} title="Remove" danger><Trash2 size={14} /></IconBtn>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function ClientAccountsView({ clients, allUsers, onManageSubscription }) {
  const [expandedUid, setExpandedUid] = useState(null);
  const today = new Date();
  const [reportMonth, setReportMonth] = useState(today.getMonth() + 1);
  const [reportYear, setReportYear] = useState(today.getFullYear());

  const staffFor = (clientUid) => allUsers.filter((u) => u.role === 'staff' && u.parentId === clientUid);
  const staffCountFor = (clientUid) => staffFor(clientUid).length;

  const expiringWarnings = useMemo(() => {
    return clients
      .map((c) => ({ client: c, days: daysUntilExpiration(c.subscription) }))
      .filter((x) => x.days !== null && x.days >= 0 && x.days <= 5);
  }, [clients]);

  // --- Reports --------------------------------------------------------
  // All six reuse the same downloadCSV helper used everywhere else in the
  // app - CSV opens fine in Excel, so no separate library/format needed.
  const clientRow = (c) => {
    const latest = getLatestSubscriptionPeriod(c.subscription);
    return {
      name: c.fullName || '—', email: c.email, staff: staffCountFor(c.id),
      period: latest ? `${MONTH_NAMES[latest.month - 1]} ${latest.year}` : '—',
      start: latest ? formatDate(latest.startDate) : '—',
      end: latest ? formatDate(latest.endDate) : '—',
      payment: latest ? (latest.paymentStatus === 'paid' ? 'Paid' : 'Unpaid') : '—',
      active: isSubscriptionActive(c.subscription),
      days: daysUntilExpiration(c.subscription),
    };
  };

  const downloadMonthlyReport = () => {
    const monthLabel = `${MONTH_NAMES[reportMonth - 1]} ${reportYear}`;
    const headers = ['Client', 'Email', 'Staff', 'Payment Status (this month)', 'Start', 'End'];
    const rows = clients.map((c) => {
      const p = (c.subscription?.history || []).find((x) => x.month === reportMonth && x.year === reportYear);
      return [
        c.fullName || '—', c.email, staffCountFor(c.id),
        p ? (p.paymentStatus === 'paid' ? 'Paid' : 'Unpaid') : 'No record',
        p ? formatDate(p.startDate) : '—', p ? formatDate(p.endDate) : '—',
      ];
    });
    downloadCSV(`subscription-report-${monthLabel.replace(' ', '-')}.csv`, headers, rows);
  };

  const downloadFiltered = (filename, headers, filterFn, mapFn) => {
    const rows = clients.filter(filterFn).map(mapFn);
    downloadCSV(filename, headers, rows);
  };

  const downloadPaidClients = () => downloadFiltered(
    'paid-clients.csv', ['Client', 'Email', 'Current Period', 'Expires', 'Staff'],
    (c) => { const r = clientRow(c); return r.payment === 'Paid'; },
    (c) => { const r = clientRow(c); return [r.name, r.email, r.period, r.end, r.staff]; }
  );

  const downloadUnpaidClients = () => downloadFiltered(
    'unpaid-clients.csv', ['Client', 'Email', 'Current Period', 'Expires', 'Staff'],
    (c) => { const r = clientRow(c); return r.payment === 'Unpaid'; },
    (c) => { const r = clientRow(c); return [r.name, r.email, r.period, r.end, r.staff]; }
  );

  const downloadExpiredSubscriptions = () => downloadFiltered(
    'expired-subscriptions.csv', ['Client', 'Email', 'Last Period', 'Expired On', 'Days Since Expired', 'Staff'],
    (c) => { const r = clientRow(c); return !r.active && r.period !== '—'; },
    (c) => { const r = clientRow(c); return [r.name, r.email, r.period, r.end, r.days !== null ? Math.abs(r.days) : '—', r.staff]; }
  );

  const downloadUpcomingExpiration = () => downloadFiltered(
    'upcoming-expiration.csv', ['Client', 'Email', 'Current Period', 'Expires', 'Days Remaining', 'Payment Status', 'Staff'],
    (c) => { const r = clientRow(c); return r.active && r.days !== null && r.days <= 30; },
    (c) => { const r = clientRow(c); return [r.name, r.email, r.period, r.end, r.days, r.payment, r.staff]; }
  );

  const downloadActiveSubscribers = () => downloadFiltered(
    'active-subscribers.csv', ['Client', 'Email', 'Current Period', 'Expires', 'Payment Status', 'Staff'],
    (c) => { const r = clientRow(c); return r.active; },
    (c) => { const r = clientRow(c); return [r.name, r.email, r.period, r.end, r.payment, r.staff]; }
  );

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Building2} label="Total Clients" value={clients.length} accent="var(--blueprint)" />
        <StatCard icon={CheckCircle2} label="Active Subscriptions" value={clients.filter((c) => isSubscriptionActive(c.subscription)).length} accent="var(--green)" />
        <StatCard icon={AlertTriangle} label="Expired Subscriptions" value={clients.filter((c) => !isSubscriptionActive(c.subscription)).length} accent="var(--red)" />
        <StatCard icon={User} label="Total Staff" value={allUsers.filter((u) => u.role === 'staff').length} accent="#2E5C87" />
      </div>

      {expiringWarnings.length > 0 && (
        <div style={{ ...styles.panel, marginBottom: 16, border: '1px solid rgba(232,163,61,0.4)' }}>
          <div style={styles.panelHeader}>
            <AlertTriangle size={15} color="var(--amber-deep)" />
            <span>ABOUT TO EXPIRE SUBSCRIPTIONS</span>
          </div>
          <div style={{ fontSize: 11.5, color: 'rgba(59,42,31,0.55)', marginTop: 4, marginBottom: 10 }}>
            Active subscriptions expiring within the next 5 days.
          </div>
          <div style={{ overflowX: 'auto' }}>
            <table style={styles.table} className="depot-table">
              <thead>
                <tr>
                  {['Client', 'Expires In', 'Expiration Date', 'Payment Status', 'Staff', ''].map((h) => (
                    <th key={h} style={styles.th}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {expiringWarnings
                  .slice()
                  .sort((a, b) => a.days - b.days)
                  .map(({ client, days }) => {
                    const latest = getLatestSubscriptionPeriod(client.subscription);
                    return (
                      <tr key={client.id} className="depot-row">
                        <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500 }}>
                          {client.fullName || '—'}<br />
                          <span style={{ fontFamily: "'Nunito', sans-serif", fontWeight: 400, fontSize: 11.5, color: 'rgba(59,42,31,0.55)' }}>{client.email}</span>
                        </td>
                        <td style={styles.td}>
                          <span style={{ ...styles.statusPill, background: 'rgba(232,163,61,0.14)', color: 'var(--amber-deep)' }}>
                            {days} day{days === 1 ? '' : 's'}
                          </span>
                        </td>
                        <td style={styles.td}>{latest ? formatDate(latest.endDate) : '—'}</td>
                        <td style={styles.td}>
                          {latest && (
                            <span style={{ ...styles.statusPill, background: latest.paymentStatus === 'paid' ? 'rgba(79,138,99,0.1)' : 'rgba(193,80,58,0.1)', color: latest.paymentStatus === 'paid' ? 'var(--green)' : 'var(--red)' }}>
                              {latest.paymentStatus === 'paid' ? 'Paid' : 'Unpaid'}
                            </span>
                          )}
                        </td>
                        <td style={styles.td}>{staffCountFor(client.id)}</td>
                        <td style={{ ...styles.td, textAlign: 'right' }}>
                          <button className="depot-btn" style={styles.smallAmberBtn} onClick={() => onManageSubscription(client)}>
                            Manage
                          </button>
                        </td>
                      </tr>
                    );
                  })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <div style={{ ...styles.panel, marginBottom: 16 }}>
        <div style={styles.panelHeader}>
          <Download size={15} />
          <span>SUBSCRIPTION REPORTS</span>
        </div>
        <div style={{ display: 'flex', gap: 10, alignItems: 'flex-end', flexWrap: 'wrap', marginTop: 12, marginBottom: 14 }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 4 }}>Monthly Subscription Report</div>
            <div style={{ display: 'flex', gap: 6 }}>
              <select className="depot-select" value={reportMonth} onChange={(e) => setReportMonth(Number(e.target.value))} style={{ ...styles.select, padding: '7px 8px' }}>
                {MONTH_NAMES.map((m, i) => <option key={m} value={i + 1}>{m}</option>)}
              </select>
              <input className="depot-input" type="number" value={reportYear} onChange={(e) => setReportYear(Number(e.target.value))} style={{ ...styles.select, width: 80, padding: '7px 8px' }} />
              <button className="depot-btn" style={styles.smallAmberBtn} onClick={downloadMonthlyReport}>
                <Download size={13} /> Export
              </button>
            </div>
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          <button className="depot-btn" style={styles.smallAmberBtn} onClick={downloadPaidClients}><Download size={13} /> Paid Clients</button>
          <button className="depot-btn" style={styles.smallAmberBtn} onClick={downloadUnpaidClients}><Download size={13} /> Unpaid Clients</button>
          <button className="depot-btn" style={styles.smallAmberBtn} onClick={downloadExpiredSubscriptions}><Download size={13} /> Expired Subscriptions</button>
          <button className="depot-btn" style={styles.smallAmberBtn} onClick={downloadUpcomingExpiration}><Download size={13} /> Upcoming Expiration (30 days)</button>
          <button className="depot-btn" style={styles.smallAmberBtn} onClick={downloadActiveSubscribers}><Download size={13} /> Active Subscribers</button>
        </div>
      </div>

      {clients.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No Client Admin accounts yet.</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Client', 'Subscription', 'Start', 'Expires', 'Payment', 'Staff', ''].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {clients.map((c) => {
                const latest = getLatestSubscriptionPeriod(c.subscription);
                const active = isSubscriptionActive(c.subscription);
                const staff = staffFor(c.id);
                const isOpen = expandedUid === c.id;
                return (
                  <React.Fragment key={c.id}>
                    <tr className="depot-row">
                      <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500 }}>
                        {c.fullName || '—'}<br />
                        <span style={{ fontFamily: "'Nunito', sans-serif", fontWeight: 400, fontSize: 11.5, color: 'rgba(59,42,31,0.55)' }}>{c.email}</span>
                      </td>
                      <td style={styles.td}>
                        <span style={{ ...styles.statusPill, background: active ? 'rgba(79,138,99,0.1)' : 'rgba(193,80,58,0.1)', color: active ? 'var(--green)' : 'var(--red)' }}>
                          {active ? 'Active' : 'Expired'}
                        </span>
                      </td>
                      <td style={styles.td}>{latest ? formatDate(latest.startDate) : '—'}</td>
                      <td style={styles.td}>{latest ? formatDate(latest.endDate) : '—'}</td>
                      <td style={styles.td}>
                        {latest ? (
                          <span style={{ ...styles.statusPill, background: latest.paymentStatus === 'paid' ? 'rgba(79,138,99,0.1)' : 'rgba(232,163,61,0.14)', color: latest.paymentStatus === 'paid' ? 'var(--green)' : 'var(--amber-deep)' }}>
                            {latest.paymentStatus === 'paid' ? 'Paid' : 'Unpaid'}
                          </span>
                        ) : '—'}
                      </td>
                      <td style={styles.td}>
                        <button
                          className="depot-btn"
                          onClick={() => setExpandedUid(isOpen ? null : c.id)}
                          style={{ display: 'flex', alignItems: 'center', gap: 5, background: 'transparent', border: 'none', padding: 0, color: 'var(--blueprint)', fontSize: 13 }}
                        >
                          <ChevronDown size={14} style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s ease' }} />
                          {staff.length} staff
                        </button>
                      </td>
                      <td className="depot-no-print" style={{ ...styles.td, textAlign: 'right' }}>
                        <button className="depot-btn" style={styles.smallAmberBtn} onClick={() => onManageSubscription(c)}>
                          Manage Subscription
                        </button>
                      </td>
                    </tr>
                    {isOpen && (
                      <tr>
                        <td colSpan={7} style={{ ...styles.td, background: 'rgba(20,33,61,0.02)', padding: '10px 14px' }}>
                          {staff.length === 0 ? (
                            <div style={{ fontSize: 12, color: 'rgba(59,42,31,0.5)' }}>No staff accounts under this client yet.</div>
                          ) : (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                              {staff.map((s) => (
                                <div key={s.id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12.5 }}>
                                  <span>{s.fullName || s.email}</span>
                                  <span style={{ color: 'rgba(59,42,31,0.55)' }}>{s.approved ? 'Active' : 'Pending'}</span>
                                </div>
                              ))}
                            </div>
                          )}
                        </td>
                      </tr>
                    )}
                  </React.Fragment>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function SubscriptionModal({ client, onClose, onSave, onDelete }) {
  const today = new Date();
  const [month, setMonth] = useState(today.getMonth() + 1);
  const [year, setYear] = useState(today.getFullYear());
  const [paymentStatus, setPaymentStatus] = useState('unpaid');
  const [busy, setBusy] = useState(false);

  const defaultPeriod = computeSubscriptionPeriod(today.getMonth() + 1, today.getFullYear());
  const [startDateStr, setStartDateStr] = useState(timestampToDateInputValue(defaultPeriod.start));
  const [endDateStr, setEndDateStr] = useState(timestampToDateInputValue(defaultPeriod.end));

  const history = (client.subscription?.history || []).slice().sort((a, b) => (b.year - a.year) || (b.month - a.month));
  const existing = history.find((p) => p.month === month && p.year === year);

  // Changing Month/Year re-fills the date pickers with that calendar
  // month's defaults (or the existing period's real dates, if one's
  // already saved for that month) - a convenient starting point that can
  // still be adjusted freely afterward.
  const handleMonthYearChange = (newMonth, newYear) => {
    setMonth(newMonth); setYear(newYear);
    const match = history.find((p) => p.month === newMonth && p.year === newYear);
    if (match) {
      setStartDateStr(timestampToDateInputValue(match.startDate));
      setEndDateStr(timestampToDateInputValue(match.endDate));
      setPaymentStatus(match.paymentStatus);
    } else {
      const period = computeSubscriptionPeriod(newMonth, newYear);
      setStartDateStr(timestampToDateInputValue(period.start));
      setEndDateStr(timestampToDateInputValue(period.end));
    }
  };

  const loadPeriod = (p) => {
    setMonth(p.month); setYear(p.year); setPaymentStatus(p.paymentStatus);
    setStartDateStr(timestampToDateInputValue(p.startDate));
    setEndDateStr(timestampToDateInputValue(p.endDate));
  };

  const startTs = dateInputValueToTimestamp(startDateStr, false);
  const endTs = dateInputValueToTimestamp(endDateStr, true);
  const datesValid = startTs && endTs && endTs >= startTs;

  const submit = async (e) => {
    e.preventDefault();
    if (!datesValid) return;
    setBusy(true);
    await onSave(client.id, { month, year, startDate: startTs, endDate: endTs, paymentStatus });
    setBusy(false);
  };

  return (
    <div style={styles.overlay}>
      <div style={{ ...styles.modal, maxWidth: 520 }} className="depot-modal" onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <span>MANAGE SUBSCRIPTION — {client.fullName || client.email}</span>
          <button className="depot-btn" onClick={onClose} style={styles.closeBtn}><X size={16} /></button>
        </div>
        <form onSubmit={submit}>
          <div style={styles.modalBody}>
            <div style={{ display: 'flex', gap: 12 }} className="depot-modal-body-row">
              <Field label="Month" grow>
                <select className="depot-select" style={styles.modalInput} value={month} onChange={(e) => handleMonthYearChange(Number(e.target.value), year)}>
                  {MONTH_NAMES.map((m, i) => <option key={m} value={i + 1}>{m}</option>)}
                </select>
              </Field>
              <Field label="Year" grow>
                <input className="depot-input" type="number" style={styles.modalInput} value={year} onChange={(e) => handleMonthYearChange(month, Number(e.target.value))} />
              </Field>
            </div>
            <div style={{ fontSize: 11, color: 'rgba(59,42,31,0.5)', marginBottom: 10 }}>
              Month/Year files this period for reports and history &mdash; the actual dates below are fully adjustable and don't have to match the calendar month.
            </div>
            <div style={{ display: 'flex', gap: 12 }} className="depot-modal-body-row">
              <Field label="Start Date" grow>
                <input className="depot-input" type="date" style={styles.modalInput} value={startDateStr} onChange={(e) => setStartDateStr(e.target.value)} />
              </Field>
              <Field label="End Date" grow>
                <input className="depot-input" type="date" style={styles.modalInput} value={endDateStr} onChange={(e) => setEndDateStr(e.target.value)} />
              </Field>
            </div>
            {!datesValid && (
              <div style={{ fontSize: 12, color: 'var(--red)', marginBottom: 6 }}>End date must be on or after the start date.</div>
            )}
            <div style={{ fontSize: 11.5, color: 'rgba(59,42,31,0.55)', marginBottom: 10 }}>
              {existing ? 'A period already exists for this month — saving will update it.' : 'This will be saved as a new period.'}
            </div>
            <Field label="Payment Status">
              <div style={{ display: 'flex', gap: 8 }}>
                <button type="button" onClick={() => setPaymentStatus('paid')}
                  className="depot-btn"
                  style={{
                    flex: 1, padding: '10px 0', borderRadius: 6, fontSize: 13, fontWeight: 600,
                    background: paymentStatus === 'paid' ? 'var(--green)' : 'transparent',
                    color: paymentStatus === 'paid' ? '#fff' : 'var(--ink)',
                    border: `1px solid ${paymentStatus === 'paid' ? 'var(--green)' : 'rgba(59,42,31,0.2)'}`,
                  }}>
                  Mark as Paid
                </button>
                <button type="button" onClick={() => setPaymentStatus('unpaid')}
                  className="depot-btn"
                  style={{
                    flex: 1, padding: '10px 0', borderRadius: 6, fontSize: 13, fontWeight: 600,
                    background: paymentStatus === 'unpaid' ? 'var(--red)' : 'transparent',
                    color: paymentStatus === 'unpaid' ? '#fff' : 'var(--ink)',
                    border: `1px solid ${paymentStatus === 'unpaid' ? 'var(--red)' : 'rgba(59,42,31,0.2)'}`,
                  }}>
                  Mark as Unpaid
                </button>
              </div>
            </Field>

            {history.length > 0 && (
              <div style={{ marginTop: 16 }}>
                <div style={{ fontSize: 12, fontWeight: 600, marginBottom: 6 }}>Subscription History</div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 4, maxHeight: 160, overflowY: 'auto' }} className="depot-scroll">
                  {history.map((p) => (
                    <div
                      key={`${p.year}-${p.month}`}
                      style={{
                        display: 'flex', alignItems: 'center', gap: 6, borderRadius: 6,
                        background: (p.month === month && p.year === year) ? 'rgba(15,42,71,0.06)' : 'transparent',
                        border: '1px solid rgba(59,42,31,0.1)',
                      }}
                    >
                      <button
                        type="button"
                        onClick={() => loadPeriod(p)}
                        className="depot-btn"
                        style={{
                          flex: 1, display: 'flex', justifyContent: 'space-between', padding: '6px 10px',
                          background: 'transparent', border: 'none', fontSize: 12, textAlign: 'left',
                        }}
                      >
                        <span>{MONTH_NAMES[p.month - 1]} {p.year}</span>
                        <span style={{ color: p.paymentStatus === 'paid' ? 'var(--green)' : 'var(--amber-deep)', fontWeight: 600 }}>
                          {p.paymentStatus === 'paid' ? 'Paid' : 'Unpaid'}
                        </span>
                      </button>
                      <IconBtn onClick={() => onDelete(p)} title="Delete this record" danger>
                        <Trash2 size={13} />
                      </IconBtn>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
          <div style={styles.modalFooter}>
            <button type="button" className="depot-btn" style={styles.ghostBtn} onClick={onClose}>Cancel</button>
            <button type="submit" className="depot-btn" style={{ ...styles.primaryBtn, opacity: (busy || !datesValid) ? 0.6 : 1 }} disabled={busy || !datesValid}>
              {busy ? 'Saving…' : 'Save Subscription'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

function SuppliersView({ suppliers, items, onEdit, onDelete }) {
  const countFor = (sid) => items.filter((it) => getSupplierIds(it).includes(sid)).length;

  const exportHeaders = ['Name', 'Contact', 'Phone', 'Email', 'Lead Time (days)', 'Items Supplied', 'Notes'];
  const exportRows = () => suppliers.map((s) => [s.name, s.contact, s.phone, s.email, s.leadTimeDays, countFor(s.id), s.notes]);
  const handleDownload = () => downloadCSV('suppliers.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('suppliers.pdf', 'Suppliers', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      {suppliers.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No suppliers yet. Add your first one.</div></div>
      ) : (
        <div style={styles.supplierGrid} className="depot-card-grid">
          {suppliers.map((s) => (
            <div key={s.id} style={styles.supplierCard}>
              <div style={styles.supplierCardHead}>
                <div style={styles.supplierIcon}><Truck size={16} color="#fff" /></div>
                <div style={{ flex: 1 }}>
                  <div style={styles.supplierName}>{s.name}</div>
                  <div style={styles.supplierMeta}>{countFor(s.id)} item{countFor(s.id) === 1 ? '' : 's'} supplied</div>
                </div>
                <div className="depot-no-print" style={{ display: 'flex', gap: 6 }}>
                  <IconBtn onClick={() => onEdit(s)} title="Edit"><Pencil size={13} /></IconBtn>
                  <IconBtn onClick={() => onDelete(s)} title="Delete" danger><Trash2 size={13} /></IconBtn>
                </div>
              </div>
              <div style={styles.supplierBody}>
                <div style={styles.supplierRow}><User size={13} /> {s.contact || '—'}</div>
                <div style={styles.supplierRow}><Phone size={13} /> {s.phone || '—'}</div>
                <div style={styles.supplierRow}><Mail size={13} /> {s.email || '—'}</div>
                <div style={styles.supplierRow}><Timer size={13} /> {s.leadTimeDays} day lead time</div>
                {s.notes && <div style={styles.supplierNotes}>{s.notes}</div>}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function OrdersView({ orders, onReceive, onCancel }) {
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');

  const filtered = useMemo(() => {
    return orders.filter((o) => {
      const matchesStatus = statusFilter === 'All' || o.status === statusFilter.toLowerCase();
      const q = search.toLowerCase();
      const matchesSearch = !q || o.itemSku.toLowerCase().includes(q) || o.itemName.toLowerCase().includes(q)
        || o.supplierName.toLowerCase().includes(q);
      return matchesStatus && matchesSearch;
    });
  }, [orders, search, statusFilter]);

  const statusStyle = (status) => {
    if (status === 'pending') return { bg: 'rgba(15,42,71,0.08)', color: 'var(--blueprint)' };
    if (status === 'cancelled') return { bg: 'rgba(193,84,60,0.1)', color: 'var(--red)' };
    return { bg: 'rgba(79,138,99,0.1)', color: 'var(--green)' }; // received
  };

  const exportHeaders = ['Order Date', 'Item', 'Supplier', 'Quantity', 'Unit Cost', 'Total', 'Expected By', 'Status', 'Notes'];
  const exportRows = () => filtered.map((o) => [
    formatDate(o.orderDate), `${o.itemSku} — ${o.itemName}`, o.supplierName, o.quantity,
    o.unitCost.toFixed(2), o.totalCost.toFixed(2), formatDate(o.expectedDate), o.status, o.notes || '',
  ]);
  const handleDownload = () => downloadCSV('orders.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('orders.pdf', 'Orders', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search by item or supplier…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <select className="depot-select" value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} style={styles.select}>
          <option value="All">All Statuses</option>
          <option value="Pending">Pending</option>
          <option value="Received">Received</option>
          <option value="Cancelled">Cancelled</option>
        </select>
      </div>

      <div style={styles.tableWrap} className="depot-scroll">
        <table style={styles.table} className="depot-table">
          <thead>
            <tr>
              {['Order Date', 'Item', 'Supplier', 'Qty', 'Unit Cost', 'Total', 'Expected By', 'Status', ''].map((h) => (
                <th key={h} style={styles.th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={9} style={{ ...styles.td, textAlign: 'center', padding: '32px 0', color: 'rgba(59,42,31,0.5)' }}>No orders match your filters.</td></tr>
            )}
            {filtered.map((o) => {
              const st = statusStyle(o.status);
              return (
                <tr key={o.id} className="depot-row">
                  <td style={styles.td}>{formatDate(o.orderDate)}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif" }}>
                    {o.itemSku} <span style={{ fontFamily: "'Nunito', sans-serif", color: 'rgba(59,42,31,0.55)' }}>— {o.itemName}</span>
                  </td>
                  <td style={styles.td}>{o.supplierName}</td>
                  <td style={styles.td}>{o.quantity}</td>
                  <td style={styles.td}>{currency(o.unitCost)}</td>
                  <td style={styles.td}>{currency(o.totalCost)}</td>
                  <td style={styles.td}>{formatDate(o.expectedDate)}</td>
                  <td style={styles.td}>
                    <span style={{ ...styles.statusPill, background: st.bg, color: st.color }}>
                      {o.status === 'received' && <CheckCircle2 size={12} />}
                      {o.status.charAt(0).toUpperCase() + o.status.slice(1)}
                    </span>
                  </td>
                  <td className="depot-no-print" style={{ ...styles.td, display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                    {o.status === 'pending' && (
                      <>
                        <IconBtn onClick={() => onReceive(o)} title="Mark received"><CheckCircle2 size={14} /></IconBtn>
                        <IconBtn onClick={() => onCancel(o)} title="Cancel order" danger><X size={14} /></IconBtn>
                      </>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function CategoriesView({ categories, items, onAdd, onDelete }) {
  const [name, setName] = useState('');
  const countFor = (cat) => items.filter((it) => it.category === cat).length;

  const submit = () => {
    onAdd(name);
    setName('');
  };

  const exportHeaders = ['Category', 'Item Count'];
  const exportRows = () => categories.map((cat) => [cat, countFor(cat)]);
  const handleDownload = () => downloadCSV('categories.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('categories.pdf', 'Categories', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Tag size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="New category name…"
            value={name}
            onChange={(e) => setName(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') submit(); }}
            style={styles.searchInput}
          />
        </div>
        <button className="depot-btn" style={{ ...styles.primaryBtn, opacity: name.trim() ? 1 : 0.45 }}
          disabled={!name.trim()} onClick={submit}>
          <Plus size={16} /> Add Category
        </button>
      </div>

      {categories.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No categories yet. Add your first one above.</div></div>
      ) : (
        <div style={styles.supplierGrid} className="depot-card-grid">
          {categories.map((cat) => {
            const count = countFor(cat);
            return (
              <div key={cat} style={styles.categoryCard}>
                <div style={styles.categoryIcon}><Tag size={16} color="#fff" /></div>
                <div style={{ flex: 1 }}>
                  <div style={styles.supplierName}>{cat}</div>
                  <div style={styles.supplierMeta}>{count} item{count === 1 ? '' : 's'}</div>
                </div>
                <IconBtn className="depot-no-print" onClick={() => onDelete(cat)} title={count > 0 ? 'Reassign items before removing' : 'Delete'} danger>
                  <Trash2 size={13} />
                </IconBtn>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

