function DeliveryTimesView({ rows, onUpdateStatus, onViewHistory }) {
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [search, setSearch] = useState('');
  const [expandedKey, setExpandedKey] = useState(null);

  // Rows without a recorded delivery yet (e.g. brand-new items) have nothing
  // to compare against a date range, so they stay visible regardless -
  // hiding them would make "Reorder Now" items disappear from a filtered view.
  const dateFiltered = useMemo(
    () => rows.filter((r) => !r.lastDelivery || inDateRange(r.lastDelivery, dateFrom, dateTo)),
    [rows, dateFrom, dateTo]
  );

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return dateFiltered;
    return dateFiltered.filter((r) => r.item.sku.toLowerCase().includes(q) || r.item.name.toLowerCase().includes(q));
  }, [dateFiltered, search]);

  const statusStyle = (status) => {
    if (status === 'Reorder Now' || status === 'Delayed') return { bg: 'rgba(193,84,60,0.1)', color: 'var(--red)' };
    if (status === 'Delivery Overdue') return { bg: 'rgba(232,163,61,0.14)', color: 'var(--amber-deep)' };
    if (status === 'In Transit' || status === 'Ordered') return { bg: 'rgba(15,42,71,0.08)', color: 'var(--blueprint)' };
    return { bg: 'rgba(79,138,99,0.1)', color: 'var(--green)' };
  };

  const exportHeaders = ['Supplier', 'SKU', 'Item', 'Order Date', 'Receive Date', 'Qty Received', 'Status', 'Manually Set', 'Note'];
  const exportRows = () => filtered.map(({ item, supplier, lastDelivery, lastDeliveryQty, orderDate, status, manual, note }) => [
    supplier.name, item.sku, item.name, formatDate(orderDate), formatDate(lastDelivery), lastDeliveryQty ?? '', status, manual ? 'Yes' : 'No', note,
  ]);
  const handleDownload = () => downloadCSV('delivery-times.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('delivery-times.pdf', 'Delivery Times', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      <div style={{ ...styles.filterBar, marginBottom: 12 }} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search by item name or SKU…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <DateRangeFilter from={dateFrom} to={dateTo} onFrom={setDateFrom} onTo={setDateTo} />
        <div style={{ ...styles.watchName, alignSelf: 'center' }}>filters by Receive Date</div>
      </div>
      <div style={styles.tableWrap} className="depot-scroll">
        <table style={styles.table} className="depot-table">
          <thead>
            <tr>
              {['Supplier', 'Item', 'Qty Received', 'Order Date', 'Received', 'Status', ''].map((h) => (
                <th key={h} style={styles.th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={7} style={{ ...styles.td, textAlign: 'center', padding: '32px 0', color: 'rgba(59,42,31,0.5)' }}>No items match your filters.</td></tr>
            )}
            {filtered.map((row) => {
              const { item, supplier, lastDelivery, lastDeliveryQty, orderDate, status, manual, log } = row;
              const key = `${item.id}-${supplier.id}`;
              const isOpen = expandedKey === key;
              const st = statusStyle(status);
              return (
                <React.Fragment key={key}>
                <tr className="depot-row">
                  <td style={styles.td}>{supplier.name}</td>
                  <td style={styles.td}>
                    <button
                      className="depot-btn"
                      onClick={() => setExpandedKey(isOpen ? null : key)}
                      style={{
                        display: 'flex', alignItems: 'center', gap: 5, background: 'transparent',
                        border: 'none', padding: 0, textAlign: 'left', color: 'var(--ink)', fontFamily: "'Quicksand', sans-serif",
                      }}
                    >
                      <ChevronDown size={14} className="depot-no-print" style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s ease', flexShrink: 0 }} />
                      <span>{item.sku} <span style={{ fontFamily: "'Nunito', sans-serif", color: 'rgba(59,42,31,0.55)' }}>— {item.name}</span></span>
                    </button>
                  </td>
                  <td style={styles.td}>{lastDeliveryQty ?? '—'}</td>
                  <td style={styles.td}>{formatDate(orderDate)}</td>
                  <td style={styles.td}>
                    {lastDelivery
                      ? new Date(lastDelivery).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' })
                      : '—'}
                  </td>
                  <td style={styles.td}>
                    <span style={{ ...styles.statusPill, background: st.bg, color: st.color }}>
                      {status === 'On Track' && <CheckCircle2 size={12} />}
                      {status !== 'On Track' && <AlertTriangle size={12} />}
                      {status}
                    </span>
                    {manual && <span style={styles.manualBadge}>manually set</span>}
                  </td>
                  <td className="depot-no-print" style={{ ...styles.td, textAlign: 'right' }}>
                    <IconBtn onClick={() => onViewHistory(item.id)} title="View full history for this item"><ScrollText size={13} /></IconBtn>
                    <IconBtn onClick={() => onUpdateStatus(row)} title="Update delivery status"><Pencil size={13} /></IconBtn>
                  </td>
                </tr>
                {isOpen && (
                  <tr className="depot-row">
                    <td colSpan={7} style={{ ...styles.td, background: 'rgba(20,33,61,0.02)', padding: '10px 14px' }}>
                      {log.length === 0 ? (
                        <div style={{ fontSize: 12, color: 'rgba(59,42,31,0.5)' }}>No delivery log yet for this item.</div>
                      ) : (
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                          <thead>
                            <tr>
                              {['Date', 'Time', 'Qty Received', 'Log'].map((h) => (
                                <th key={h} style={{ ...styles.th, padding: '4px 8px', fontSize: 10.5 }}>{h}</th>
                              ))}
                            </tr>
                          </thead>
                          <tbody>
                            {log.map((m) => (
                              <tr key={m.id}>
                                <td style={{ padding: '4px 8px', fontSize: 12 }}>
                                  {new Date(m.timestamp).toLocaleDateString('en-PH', { month: 'short', day: 'numeric', year: 'numeric' })}
                                </td>
                                <td style={{ padding: '4px 8px', fontSize: 12, fontFamily: "'IBM Plex Mono', monospace" }}>
                                  {new Date(m.timestamp).toLocaleTimeString('en-PH', { hour: '2-digit', minute: '2-digit' })}
                                </td>
                                <td style={{ padding: '4px 8px', fontSize: 12, fontWeight: 600 }}>{m.qty}</td>
                                <td style={{ padding: '4px 8px', fontSize: 12, color: 'rgba(59,42,31,0.7)' }}>{m.reason}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      )}
                    </td>
                  </tr>
                )}
                </React.Fragment>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function POSView({ items, onCompleteSale, shops, activeShopId, onSwitchShop }) {
  const [search, setSearch] = useState('');
  const [cart, setCart] = useState([]); // [{itemId, qty}]
  const [lastReceipt, setLastReceipt] = useState(null);
  const [confirming, setConfirming] = useState(false);
  const [amountReceived, setAmountReceived] = useState('');

  const sellable = useMemo(() => items.filter((it) => it.quantity > 0), [items]);
  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return sellable.filter((it) => it.sku.toLowerCase().includes(q) || it.name.toLowerCase().includes(q));
  }, [sellable, search]);

  const itemMap = useMemo(() => Object.fromEntries(items.map((i) => [i.id, i])), [items]);
  // Which unit is currently selected on each item's card, keyed by item id
  // (index into that item's getItemUnits() list; 0 = base unit).
  const [unitChoice, setUnitChoice] = useState({});

  // Base-unit stock already committed to the cart for a given item, across
  // every unit it might be present as - needed so mixing e.g. a Box/Case
  // and some loose Pieces of the same item in one sale can't oversell it.
  const cartBaseUsage = (prev, itemId, excludeKey) =>
    prev.filter((l) => l.itemId === itemId && l.key !== excludeKey).reduce((s, l) => s + l.factor * l.qty, 0);

  const addToCart = (item, unit) => {
    setLastReceipt(null);
    const key = `${item.id}:${unit.name}`;
    setCart((prev) => {
      const used = cartBaseUsage(prev, item.id, null);
      const remaining = item.quantity - used;
      if (remaining < unit.factor) return prev;
      const existing = prev.find((l) => l.key === key);
      if (existing) return prev.map((l) => l.key === key ? { ...l, qty: l.qty + 1 } : l);
      return [...prev, {
        key, itemId: item.id, sku: item.sku, name: item.name,
        unitName: unit.name, factor: unit.factor, unitPrice: unit.price, unitCost: item.unitCost, qty: 1,
      }];
    });
  };

  const changeQty = (key, itemId, factor, delta) => {
    setCart((prev) => {
      const item = itemMap[itemId];
      const used = cartBaseUsage(prev, itemId, key);
      const maxUnits = item ? Math.max(1, Math.floor((item.quantity - used) / factor)) : Infinity;
      return prev.map((l) => l.key === key ? { ...l, qty: Math.min(maxUnits, Math.max(1, l.qty + delta)) } : l);
    });
  };

  const removeLine = (key) => setCart((prev) => prev.filter((l) => l.key !== key));

  // Bluetooth/USB scanner support: a scan is treated exactly like tapping
  // the matching item card. Works regardless of what's focused on screen,
  // so cashiers can scan items in quick succession without clicking back
  // into a search box between each one.
  const [scanMsg, setScanMsg] = useState(null);
  useEffect(() => {
    if (!scanMsg) return;
    const t = setTimeout(() => setScanMsg(null), 2200);
    return () => clearTimeout(t);
  }, [scanMsg]);

  const handleScan = (code) => {
    const found = findItemByScan(sellable, code);
    if (found) {
      addToCart(found, getItemUnits(found)[0]);
      setScanMsg({ ok: true, text: `Scanned: ${found.name}` });
    } else {
      setScanMsg({ ok: false, text: `No item matches barcode ${code}` });
    }
  };
  useBarcodeScanner(handleScan, true);

  const subtotal = cart.reduce((s, l) => s + l.unitPrice * l.qty, 0);
  const total = subtotal;
  const receivedNum = amountReceived === '' ? null : Number(amountReceived);
  const change = receivedNum != null ? receivedNum - total : null;
  const billValid = receivedNum != null && receivedNum >= total;

  const [busy, setBusy] = useState(false);

  const checkout = async () => {
    setBusy(true);
    try {
      const sale = await onCompleteSale(cart, amountReceived);
      if (sale) {
        setLastReceipt(sale);
        setCart([]);
        setAmountReceived('');
      }
    } finally {
      setBusy(false);
      setConfirming(false);
    }
  };

  return (
    <div style={{ animation: 'fadeIn 0.3s ease', display: 'grid', gridTemplateColumns: '1.4fr 1fr', gap: 16, alignItems: 'start' }} className="depot-pos-layout">
      <div>
        {shops && shops.length > 0 && (
          <div style={{
            display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12, padding: '9px 12px',
            background: '#fff', border: '1px solid rgba(59,42,31,0.15)', borderRadius: 6,
          }}>
            <Store size={15} color="var(--amber)" />
            <span style={{ fontSize: 12.5, fontWeight: 700, color: 'rgba(59,42,31,0.6)' }}>Selling from:</span>
            <select
              className="depot-select" value={activeShopId || ''} onChange={(e) => onSwitchShop(e.target.value)}
              style={{ ...styles.modalInput, width: 220, padding: '6px 10px' }}
            >
              {shops.map((s) => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
            <span style={{ fontSize: 11, color: 'rgba(59,42,31,0.45)' }}>All sales and stock deductions apply to this shop.</span>
          </div>
        )}
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search items to sell…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
          <span style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: 11, color: 'rgba(59,42,31,0.4)', whiteSpace: 'nowrap', paddingRight: 4 }} title="A paired Bluetooth or USB barcode scanner will add items automatically">
            <Bluetooth size={13} /> Scanner ready
          </span>
        </div>
        {scanMsg && (
          <div style={{
            marginTop: 8, padding: '7px 12px', borderRadius: 6, fontSize: 12.5, fontWeight: 600,
            background: scanMsg.ok ? 'rgba(79,138,99,0.12)' : 'rgba(193,80,58,0.12)',
            color: scanMsg.ok ? 'var(--green)' : 'var(--red)',
            display: 'flex', alignItems: 'center', gap: 6, animation: 'fadeIn 0.15s ease',
          }}>
            <ScanLine size={14} /> {scanMsg.text}
          </div>
        )}
        <div style={styles.posGrid} className="depot-pos-grid">
          {filtered.length === 0 && (
            <div style={styles.emptyState}>No sellable items match your search.</div>
          )}
          {filtered.map((it) => {
            const units = getItemUnits(it);
            const defaultIdx = Math.max(0, units.findIndex((u) => u.name === it.defaultSellingUnit));
            const choiceIdx = Math.min(unitChoice[it.id] ?? defaultIdx, units.length - 1);
            const unit = units[choiceIdx];
            const stockInUnit = unit.factor > 0 ? Math.floor((it.quantity || 0) / unit.factor) : 0;
            return (
              <div key={it.id} className="depot-btn" style={{ ...styles.posItemCard, cursor: 'default' }}>
                <div style={styles.posItemSku}>{it.sku}</div>
                <div style={styles.posItemName}>{it.name}</div>
                {units.length > 1 && (
                  <select
                    className="depot-select" style={{ ...styles.modalInput, fontSize: 11.5, padding: '4px 8px', marginTop: 4, marginBottom: 4 }}
                    value={choiceIdx} onClick={(e) => e.stopPropagation()}
                    onChange={(e) => setUnitChoice((prev) => ({ ...prev, [it.id]: Number(e.target.value) }))}
                  >
                    {units.map((u, i) => <option key={u.name} value={i}>{u.name}</option>)}
                  </select>
                )}
                <div style={styles.posItemFooter}>
                  <span>{currency(unit.price)}</span>
                  <span style={{ color: stockInUnit > 0 ? 'rgba(59,42,31,0.5)' : 'var(--red)' }}>
                    {stockInUnit} {unit.name}{stockInUnit === 1 ? '' : 's'}
                  </span>
                </div>
                <button
                  className="depot-btn" style={{ ...styles.primaryBtn, width: '100%', justifyContent: 'center', marginTop: 6, padding: '6px 10px', fontSize: 12, opacity: stockInUnit > 0 ? 1 : 0.4 }}
                  disabled={stockInUnit <= 0} onClick={() => addToCart(it, unit)}
                >
                  <Plus size={13} /> Add
                </button>
              </div>
            );
          })}
        </div>
      </div>

      <div style={styles.cartPanel} className="depot-cart-panel">
        <div style={styles.panelHeader}>
          <ShoppingCart size={15} />
          <span>CURRENT SALE</span>
        </div>

        {cart.length === 0 ? (
          <div style={styles.emptyState}>Tap an item to add it to the sale.</div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
            {cart.map((line) => (
              <div key={line.key} style={styles.cartLine}>
                <div style={{ flex: 1 }}>
                  <div style={styles.watchSku}>{line.sku}</div>
                  <div style={styles.watchName}>{line.name}</div>
                  <div style={{ fontSize: 11, color: 'rgba(59,42,31,0.5)' }}>{currency(line.unitPrice)} / {line.unitName}</div>
                </div>
                <div style={styles.qtyStepper}>
                  <button className="depot-btn" style={styles.qtyBtn} onClick={() => changeQty(line.key, line.itemId, line.factor, -1)}><Minus size={12} /></button>
                  <span style={styles.qtyValue}>{line.qty}</span>
                  <button className="depot-btn" style={styles.qtyBtn} onClick={() => changeQty(line.key, line.itemId, line.factor, 1)}><Plus size={12} /></button>
                </div>
                <div style={{ width: 72, textAlign: 'right', fontFamily: "'Quicksand', sans-serif", fontSize: 12.5 }}>
                  {currency(line.unitPrice * line.qty)}
                </div>
                <IconBtn onClick={() => removeLine(line.key)} title="Remove" danger><X size={13} /></IconBtn>
              </div>
            ))}
          </div>
        )}

        <div style={styles.cartTotals}>
          <div style={styles.cartTotalsRow}><span>Subtotal</span><span>{currency(subtotal)}</span></div>
          <div style={{ ...styles.cartTotalsRow, ...styles.cartTotalsFinal }}><span>Total</span><span>{currency(total)}</span></div>
        </div>

        {cart.length > 0 && (
          <div style={{ marginTop: 10 }}>
            <Field label="Bill (Amount Received)">
              <input
                className="depot-input" type="number" step="0.01" min="0" style={styles.modalInput}
                placeholder="0.00" value={amountReceived}
                onChange={(e) => setAmountReceived(e.target.value === '' ? '' : Math.max(0, Number(e.target.value)))}
              />
            </Field>
            {receivedNum != null && (
              <div style={{
                ...styles.cartTotalsRow, fontWeight: 700,
                color: billValid ? 'var(--green)' : 'var(--red)',
              }}>
                <span>{billValid ? 'Change' : 'Insufficient — short by'}</span>
                <span>{currency(Math.abs(change))}</span>
              </div>
            )}
          </div>
        )}

        <button className="depot-btn" style={{ ...styles.primaryBtn, width: '100%', justifyContent: 'center', marginTop: 12, opacity: cart.length && billValid && !busy ? 1 : 0.45 }}
          disabled={!cart.length || !billValid || busy} onClick={() => setConfirming(true)}>
          <Receipt size={16} /> Confirm Sale
        </button>
      </div>

      {confirming && (
        <ConfirmModal
          title="CONFIRM SALE"
          message={<>Are you sure you want to complete this sale for <strong>{currency(total)}</strong>? Bill: <strong>{currency(receivedNum)}</strong>, Change: <strong>{currency(change)}</strong>. This will deduct the sold quantities from stock.</>}
          onCancel={() => setConfirming(false)}
          onConfirm={checkout}
          confirmLabel={busy ? 'Processing…' : 'Confirm Sale'}
          danger={false}
        />
      )}

      {lastReceipt && (
        <SaleReceiptModal sale={lastReceipt} onClose={() => setLastReceipt(null)} />
      )}
    </div>
  );
}

function SalesHistoryView({ sales, role, onCancelSale, onDeleteSale, onLogActivity }) {
  const canCancel = can(role, 'cancelSales');
  const canDeleteSale = role === 'client';
  const [cashierFilter, setCashierFilter] = useState('All');
  const [expandedId, setExpandedId] = useState(null);
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const [search, setSearch] = useState('');

  // Filtering/grouping keys off the stable cashierEmail (always present),
  // but everything actually DISPLAYED uses the username when available.
  const cashierLabel = (sale) => sale.cashierUsername || sale.cashierEmail || 'Unknown';
  const totalQtyFor = (sale) => sale.items.reduce((sum, l) => sum + l.qty, 0);

  const dateFiltered = useMemo(() => sales.filter((s) => inDateRange(s.timestamp, dateFrom, dateTo)), [sales, dateFrom, dateTo]);

  // Matches if ANY line item in the sale has a matching SKU or name.
  const searchFiltered = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return dateFiltered;
    return dateFiltered.filter((s) => s.items.some((l) => l.sku.toLowerCase().includes(q) || l.name.toLowerCase().includes(q)));
  }, [dateFiltered, search]);

  const cashiers = useMemo(() => {
    const map = new Map();
    searchFiltered.forEach((s) => { if (s.cashierEmail) map.set(s.cashierEmail, cashierLabel(s)); });
    return Array.from(map.entries()).sort((a, b) => a[1].localeCompare(b[1])); // [email, label]
  }, [searchFiltered]);

  const filtered = useMemo(() => {
    if (cashierFilter === 'All') return searchFiltered;
    return searchFiltered.filter((s) => s.cashierEmail === cashierFilter);
  }, [searchFiltered, cashierFilter]);

  const overall = useMemo(() => {
    const active = dateFiltered.filter((s) => !s.cancelled);
    return { count: active.length, total: active.reduce((sum, s) => sum + s.total, 0) };
  }, [dateFiltered]);

  const byCashier = useMemo(() => {
    const map = {};
    dateFiltered.forEach((s) => {
      if (s.cancelled) return;
      const key = s.cashierEmail || 'Unknown';
      if (!map[key]) map[key] = { label: cashierLabel(s), count: 0, total: 0 };
      map[key].count += 1;
      map[key].total += s.total;
    });
    return Object.entries(map)
      .map(([key, v]) => ({ key, ...v }))
      .sort((a, b) => b.total - a.total);
  }, [dateFiltered]);

  const exportHeaders = ['Receipt', 'Date', 'Cashier', 'Items Sold', 'Quantity Sold', 'Subtotal', 'Total', 'Status'];
  const exportRows = () => filtered.map((sale) => [
    sale.receiptNo,
    new Date(sale.timestamp).toLocaleString('en-PH'),
    cashierLabel(sale),
    sale.items.map((l) => `${l.qty}${l.unitName ? ' ' + l.unitName : ''}x ${l.sku}`).join('; '),
    totalQtyFor(sale),
    sale.subtotal.toFixed(2),
    sale.total.toFixed(2),
    sale.cancelled ? 'Cancelled' : 'Completed',
  ]);
  const handleDownload = () => { downloadCSV('sales-history.csv', exportHeaders, exportRows()); onLogActivity?.('report_generated', { report: 'Sales History', format: 'CSV' }); };
  const handleDownloadPDF = () => { downloadPDF('sales-history.pdf', 'Sales History', exportHeaders, exportRows()); onLogActivity?.('report_generated', { report: 'Sales History', format: 'PDF' }); };

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      <div style={{ ...styles.filterBar, marginBottom: 12 }} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search by item name or SKU…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <DateRangeFilter from={dateFrom} to={dateTo} onFrom={setDateFrom} onTo={setDateTo} />
      </div>

      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 4 }}>
        {[
          { label: 'Today', days: 0 },
          { label: 'This Week', days: 7 },
          { label: 'This Month', days: 30 },
          { label: 'This Year', days: 365 },
          { label: 'All Time', days: null },
        ].map((preset) => (
          <button
            key={preset.label}
            className="depot-btn"
            style={{ ...styles.ghostBtn, padding: '6px 12px', fontSize: 12 }}
            onClick={() => {
              if (preset.days === null) { setDateFrom(''); setDateTo(''); return; }
              const to = new Date();
              const from = new Date();
              if (preset.days === 0) { from.setHours(0, 0, 0, 0); } else { from.setDate(from.getDate() - preset.days); }
              setDateFrom(timestampToDateInputValue(from.getTime()));
              setDateTo(timestampToDateInputValue(to.getTime()));
            }}
          >
            {preset.label}
          </button>
        ))}
      </div>

      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Receipt} label="Sales (Overall)" value={overall.count} accent="var(--blueprint)" />
        <StatCard icon={PesoIcon} label="Total Revenue (Overall)" value={currency(overall.total)} accent="var(--green)" />
      </div>

      {byCashier.length > 0 && (
        <div style={{ ...styles.panel, marginBottom: 16 }}>
          <div style={styles.panelHeader}>
            <User size={15} />
            <span>TOTAL SALES PER ACCOUNT</span>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
            {byCashier.map((c) => (
              <div key={c.key} style={styles.watchRow}>
                <div>
                  <div style={styles.watchSku}>{c.label}</div>
                  <div style={styles.watchName}>{c.count} sale{c.count === 1 ? '' : 's'}</div>
                </div>
                <div style={{ fontWeight: 700, fontFamily: "'Quicksand', sans-serif", color: 'var(--ink)' }}>
                  {currency(c.total)}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {cashiers.length > 0 && (
        <div style={styles.filterBar} className="depot-no-print depot-filterbar">
          <select className="depot-select" value={cashierFilter} onChange={(e) => setCashierFilter(e.target.value)} style={styles.select}>
            <option value="All">All Staff</option>
            {cashiers.map(([emailVal, label]) => <option key={emailVal} value={emailVal}>{label}</option>)}
          </select>
          {cashierFilter !== 'All' && (
            <div style={{ ...styles.watchName, alignSelf: 'center' }}>
              {filtered.length} sale{filtered.length === 1 ? '' : 's'} · {currency(filtered.reduce((s, x) => s + (x.cancelled ? 0 : x.total), 0))} total
            </div>
          )}
        </div>
      )}
      {filtered.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>{search.trim() ? 'No sales match your search.' : 'No sales recorded yet. Ring one up in Point of Sale.'}</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Receipt', 'Date', 'Cashier', 'Items Sold', 'Quantity Sold', 'Total', 'Status', ...((canCancel || canDeleteSale) ? [''] : [])].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((sale) => {
                const isOpen = expandedId === sale.id;
                const colCount = 7 + (canCancel || canDeleteSale ? 1 : 0);
                return (
                <React.Fragment key={sale.id}>
                <tr className="depot-row" style={sale.cancelled ? { opacity: 0.55 } : undefined}>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{sale.receiptNo}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontSize: 12.5 }}>
                    {new Date(sale.timestamp).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                  </td>
                  <td style={{ ...styles.td, fontSize: 12.5 }}>{cashierLabel(sale)}</td>
                  <td style={styles.td}>
                    <button
                      className="depot-btn"
                      onClick={() => setExpandedId(isOpen ? null : sale.id)}
                      style={{
                        display: 'flex', alignItems: 'center', gap: 5, background: 'transparent',
                        border: 'none', padding: 0, color: 'var(--blueprint)', fontSize: 13, fontFamily: "'Nunito', sans-serif",
                      }}
                    >
                      <ChevronDown size={14} className="depot-no-print" style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s ease' }} />
                      {sale.items.length} item{sale.items.length === 1 ? '' : 's'}
                    </button>
                  </td>
                  <td style={{ ...styles.td, fontWeight: 600 }}>{totalQtyFor(sale)}</td>
                  <td style={{ ...styles.td, fontWeight: 600, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{currency(sale.total)}</td>
                  <td style={styles.td}>
                    {sale.cancelled ? (
                      <span style={{ ...styles.statusPill, background: 'rgba(193,80,58,0.1)', color: 'var(--red)' }}>Cancelled</span>
                    ) : (
                      <span style={{ ...styles.statusPill, background: 'rgba(79,138,99,0.1)', color: 'var(--green)' }}>Completed</span>
                    )}
                  </td>
                  {(canCancel || canDeleteSale) && (
                    <td className="depot-no-print" style={{ ...styles.td, textAlign: 'right' }}>
                      {!sale.cancelled && canCancel && (
                        <button className="depot-btn" style={{ ...styles.smallAmberBtn, background: 'transparent', color: 'var(--red)', border: '1px solid rgba(193,80,58,0.3)' }} onClick={() => onCancelSale(sale)}>
                          Cancel
                        </button>
                      )}
                      {sale.cancelled && canDeleteSale && (
                        <button className="depot-btn" style={{ ...styles.smallAmberBtn, background: 'var(--red)', color: '#fff' }} onClick={() => onDeleteSale(sale)}>
                          Delete
                        </button>
                      )}
                    </td>
                  )}
                </tr>
                {isOpen && (
                  <tr className="depot-row">
                    <td colSpan={colCount} style={{ ...styles.td, background: 'rgba(20,33,61,0.02)', padding: '10px 14px' }}>
                      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                        <thead>
                          <tr>
                            {['SKU', 'Item', 'Qty', 'Unit Price', 'Line Total'].map((h) => (
                              <th key={h} style={{ ...styles.th, padding: '4px 8px', fontSize: 10.5 }}>{h}</th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {sale.items.map((l, i) => (
                            <tr key={i}>
                              <td style={{ padding: '4px 8px', fontFamily: "'Quicksand', sans-serif", fontSize: 12 }}>{l.sku}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12 }}>{l.name}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12 }}>{l.qty}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12, fontFamily: "'IBM Plex Mono', monospace" }}>{currency(l.unitPrice)}</td>
                              <td style={{ padding: '4px 8px', fontSize: 12, fontFamily: "'IBM Plex Mono', monospace", fontWeight: 600 }}>{currency(l.lineTotal)}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </td>
                  </tr>
                )}
                </React.Fragment>
                );
              })}
            </tbody>

          </table>
        </div>
      )}
    </div>
  );
}

function MySalesView({ sales }) {
  const totalToday = useMemo(() => {
    const start = new Date(); start.setHours(0, 0, 0, 0);
    return sales.filter((s) => !s.cancelled && s.timestamp >= start.getTime()).reduce((s, x) => s + x.total, 0);
  }, [sales]);
  const totalAll = useMemo(() => sales.filter((s) => !s.cancelled).reduce((s, x) => s + x.total, 0), [sales]);

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Receipt} label="Sales Recorded" value={sales.length} accent="var(--blueprint)" />
        <StatCard icon={PesoIcon} label="Total Today" value={currency(totalToday)} accent="var(--green)" />
        <StatCard icon={PesoIcon} label="Total All-Time" value={currency(totalAll)} accent="var(--amber-deep)" />
      </div>
      {sales.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>You haven't processed any sales yet. Ring one up in Point of Sale.</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Receipt', 'Date', 'Items Sold', 'Quantity Sold', 'Total', 'Status'].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {sales.map((sale) => (
                <tr key={sale.id} className="depot-row" style={sale.cancelled ? { opacity: 0.55 } : undefined}>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{sale.receiptNo}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontSize: 12.5 }}>
                    {new Date(sale.timestamp).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                  </td>
                  <td style={styles.td}>{sale.items.map((l) => `${l.qty}${l.unitName ? ' ' + l.unitName : ''}× ${l.sku}`).join(', ')}</td>
                  <td style={{ ...styles.td, fontWeight: 600 }}>{sale.items.reduce((sum, l) => sum + l.qty, 0)}</td>
                  <td style={{ ...styles.td, fontWeight: 600, textDecoration: sale.cancelled ? 'line-through' : 'none' }}>{currency(sale.total)}</td>
                  <td style={styles.td}>
                    {sale.cancelled ? (
                      <span style={{ ...styles.statusPill, background: 'rgba(193,80,58,0.1)', color: 'var(--red)' }}>Cancelled</span>
                    ) : (
                      <span style={{ ...styles.statusPill, background: 'rgba(79,138,99,0.1)', color: 'var(--green)' }}>Completed</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function ActivityLogView({ logs, myRole, approvedUsers, pendingUsers }) {
  const [userFilter, setUserFilter] = useState('All');
  const [roleFilter, setRoleFilter] = useState('All');
  const [typeFilter, setTypeFilter] = useState('All');
  const [itemFilter, setItemFilter] = useState('All');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');
  const roleByUid = useMemo(() => {
    const map = {};
    [...approvedUsers, ...pendingUsers].forEach((u) => { map[u.id] = u.role; });
    return map;
  }, [approvedUsers, pendingUsers]);

  const dateFiltered = useMemo(() => logs.filter((l) => inDateRange(l.timestamp, dateFrom, dateTo)), [logs, dateFrom, dateTo]);

  const users = useMemo(() => {
    const set = new Set(dateFiltered.map((l) => l.email).filter(Boolean));
    return Array.from(set).sort();
  }, [dateFiltered]);

  const types = useMemo(() => {
    const set = new Set(dateFiltered.map((l) => l.type).filter(Boolean));
    return Array.from(set).sort();
  }, [dateFiltered]);

  const items = useMemo(() => {
    const set = new Set(dateFiltered.map((l) => l.meta?.itemSku).filter(Boolean));
    return Array.from(set).sort();
  }, [dateFiltered]);

  const filtered = useMemo(() => {
    return dateFiltered.filter((l) => {
      const matchesUser = userFilter === 'All' || l.email === userFilter;
      const matchesRole = roleFilter === 'All' || roleByUid[l.uid] === roleFilter;
      const matchesType = typeFilter === 'All' || l.type === typeFilter;
      const matchesItem = itemFilter === 'All' || l.meta?.itemSku === itemFilter;
      return matchesUser && matchesRole && matchesType && matchesItem;
    });
  }, [dateFiltered, userFilter, roleFilter, typeFilter, itemFilter, roleByUid]);

  const exportHeaders = ['Email', 'Role', 'Type', 'Details', 'Timestamp'];
  const exportRows = () => filtered.map((l) => [
    l.email, ROLES[roleByUid[l.uid]] || '—', ACTIVITY_TYPE_LABELS[l.type] || l.type,
    describeActivity(l), new Date(l.timestamp).toLocaleString('en-PH'),
  ]);
  const handleDownload = () => downloadCSV('activity-log.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('activity-log.pdf', 'Activity Log', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      <div style={{ ...styles.filterBar, marginBottom: 8 }} className="depot-no-print depot-filterbar">
        <DateRangeFilter from={dateFrom} to={dateTo} onFrom={setDateFrom} onTo={setDateTo} />
      </div>
      <div style={{ ...styles.filterBar, flexWrap: 'wrap' }} className="depot-no-print depot-filterbar">
        {users.length > 0 && (
          <select className="depot-select" value={userFilter} onChange={(e) => setUserFilter(e.target.value)} style={styles.select}>
            <option value="All">All Users</option>
            {users.map((u) => <option key={u} value={u}>{u}</option>)}
          </select>
        )}
        <select className="depot-select" value={roleFilter} onChange={(e) => setRoleFilter(e.target.value)} style={styles.select}>
          <option value="All">All Roles</option>
          {Object.keys(ROLES).map((r) => <option key={r} value={r}>{ROLES[r]}</option>)}
        </select>
        <select className="depot-select" value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} style={styles.select}>
          <option value="All">All Activity Types</option>
          {types.map((t) => <option key={t} value={t}>{ACTIVITY_TYPE_LABELS[t] || t}</option>)}
        </select>
        {items.length > 0 && (
          <select className="depot-select" value={itemFilter} onChange={(e) => setItemFilter(e.target.value)} style={styles.select}>
            <option value="All">All Items</option>
            {items.map((sku) => <option key={sku} value={sku}>{sku}</option>)}
          </select>
        )}
      </div>
      {filtered.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No activity matches your filters.</div></div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['Email', 'Role', 'Event', 'Details', 'Timestamp'].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((l) => {
                const badge = activityBadgeColors(l.type);
                return (
                  <tr key={l.id} className="depot-row">
                    <td style={styles.td}>{l.email}</td>
                    <td style={styles.td}><span style={styles.pill}>{ROLES[roleByUid[l.uid]] || '—'}</span></td>
                    <td style={styles.td}>
                      <span style={{ ...styles.statusPill, background: badge.bg, color: badge.color }}>
                        {ACTIVITY_TYPE_LABELS[l.type] || l.type}
                      </span>
                    </td>
                    <td style={{ ...styles.td, fontSize: 12.5, color: 'rgba(59,42,31,0.75)' }}>{describeActivity(l)}</td>
                    <td style={{ ...styles.td, fontFamily: "'IBM Plex Mono', monospace", fontSize: 12.5 }}>
                      {new Date(l.timestamp).toLocaleString('en-PH', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function ProfileEditModal({ user, onClose, onSave }) {
  const [fullName, setFullName] = useState(user.fullName || '');
  const [username, setUsername] = useState(user.username || '');
  const [contactNumber, setContactNumber] = useState(user.contactNumber || '');
  const [address, setAddress] = useState(user.address || '');
  const [photoDataUri, setPhotoDataUri] = useState(undefined); // undefined = unchanged
  const [photoBusy, setPhotoBusy] = useState(false);
  const [photoError, setPhotoError] = useState('');

  const handlePhotoFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPhotoError('');
    setPhotoBusy(true);
    try {
      const resized = await resizePhotoToDataUri(file);
      setPhotoDataUri(resized);
    } catch (err) {
      setPhotoError('Could not process that image. Try a different file.');
    } finally {
      setPhotoBusy(false);
    }
  };

  const submit = () => {
    onSave(user.id, { fullName, username, contactNumber, address, photoDataUri });
    onClose();
  };

  const currentPhoto = photoDataUri !== undefined ? photoDataUri : user.photoDataUri;

  return (
    <div style={styles.overlay}>
      <div style={{ ...styles.modal, maxWidth: 400 }} className="depot-modal" onClick={(e) => e.stopPropagation()}>
        <div style={styles.modalHeader}>
          <span>EDIT PROFILE — {user.email}</span>
          <button className="depot-btn" onClick={onClose} style={styles.closeBtn}><X size={16} /></button>
        </div>
        <div style={styles.modalBody}>
          <div style={{ fontSize: 11.5, color: 'rgba(59,42,31,0.5)', marginBottom: 14, fontFamily: "'IBM Plex Mono', monospace" }}>
            ID: {user.userIdNumber || '—'} · Account: {user.id}
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 16 }}>
            <Avatar src={currentPhoto} name={fullName || user.email} size={56} />
            <div>
              <input type="file" accept="image/*" onChange={handlePhotoFile} disabled={photoBusy} style={{ fontSize: 12 }} />
              {photoBusy && <div style={{ fontSize: 11.5, color: 'rgba(59,42,31,0.5)', marginTop: 4 }}>Processing photo…</div>}
              {photoError && <div style={{ fontSize: 11.5, color: 'var(--red)', marginTop: 4 }}>{photoError}</div>}
              {currentPhoto && (
                <button
                  type="button"
                  className="depot-btn"
                  onClick={() => setPhotoDataUri(null)}
                  style={{ background: 'transparent', border: 'none', padding: 0, marginTop: 4, fontSize: 11.5, color: 'var(--red)', textDecoration: 'underline', cursor: 'pointer' }}
                >
                  Remove photo
                </button>
              )}
            </div>
          </div>

          <Field label="Full Name">
            <input className="depot-input" style={styles.modalInput} value={fullName} onChange={(e) => setFullName(e.target.value)} />
          </Field>
          <Field label="Username">
            <input className="depot-input" style={styles.modalInput} value={username} onChange={(e) => setUsername(e.target.value)} />
          </Field>
          <Field label="Contact Number">
            <input className="depot-input" style={styles.modalInput} value={contactNumber} onChange={(e) => setContactNumber(e.target.value)} />
          </Field>
          <Field label="Address">
            <input className="depot-input" style={styles.modalInput} value={address} onChange={(e) => setAddress(e.target.value)} />
          </Field>
        </div>
        <div style={styles.modalFooter}>
          <button className="depot-btn" style={styles.ghostBtn} onClick={onClose}>Cancel</button>
          <button className="depot-btn" style={styles.primaryBtn} onClick={submit} disabled={photoBusy}>Save</button>
        </div>
      </div>
    </div>
  );
}

